public static void main(String[] args) {
        FastScanner scanner = new FastScanner();
        PrintWriter out = new PrintWriter(System.out);
        int T = scanner.nextInt();
        while(T-->0) {
            int N =scanner.nextInt();
            PriorityQueue<Point> queue = new PriorityQueue<>();
            for(int i = 0; i < N; i++) {
                queue.offer(new Point(scanner.nextInt(), true, i));
                queue.offer(new Point(scanner.nextInt(), false, i));
            }
            int cur = 0;
            int assign = 1;
            int outArr[]  =new int[N];
            while(!queue.isEmpty()) {
                Point next = queue.poll();
                if (next.start) {
                    cur++;
                    outArr[next.num] = assign;
                }
                else cur--;
                if (cur == 0 && !queue.isEmpty()) {
                    assign = 2;
                }
            }
            if(assign == 1) out.println(-1);
            else {
                for (int i = 0; i < N; i++) {
                    if (i > 0) out.print(" ");
                    out.print(outArr[i]);
                }
                out.println();
            }
        }
        out.flush();
    }

