int getNumberOfTriangles2(int bigSide, int moveSmallSide, int stableSide, int dx, int dy, int n, int m, int[][][] maxLength) {
        int result = 0;
        for (int x = 0; x < n; ++x) {
            for (int y = 0; y < m; ++y) {
                for (int k = 2; ; k += 2) {
                    int sk = k / 2;
                    if (maxLength[x][y][bigSide] < k || maxLength[x][y][moveSmallSide] < sk) break;
                    int x2 = x + dx * k;
                    int y2 = y + dy * k;
                    if (valid(x2, y2, n, m)) {
                        if (maxLength[x2][y2][stableSide] >= sk) {
                            ++result;
                        }
                    } else {
                        break;
                    }
                }
            }
        }
        return result;
    }

