public static int[] readNums(BufferedReader bf) throws Exception {		
		int idx = 0, n = 0;		
		String line = bf.readLine();

		int i;
		for(i = 0; i < line.length(); i++) {
			char c = line.charAt(i);
			if(c == ' ') break;

			int d = c - '0';
			n = 10 * n + d;
		}

		int[] nums = new int[n];
		for(i = i + 1; i < line.length(); i++) {
			char c = line.charAt(i);
			if(c == ' ') idx++;
			else {
				int d = c - '0';
				nums[idx] = 10 * nums[idx] + d;
			}
		}

		return nums;
	}

static void solve(long min, long max, Map<Long, Long> pref, Map<Long, Long> suf,
                      TreeSet<Long> f, Set<Long> sums) {
        if(min > max) return;
        if(min == max) {
            Long minus = pref.get(f.lower(min));
            if(minus == null) minus = 0L;

            sums.add(pref.get(min) - minus);
            return;
        }
        Long mid = (min + max) / 2;
        Long l = f.floor(mid);
        Long r = f.higher(mid);

        if(l != null) {
            Long minus = pref.get(f.lower(min));
            if(minus == null) minus = 0L;

            sums.add(pref.get(l) - minus);
            solve(min, l, pref, suf, f, sums);
        }

        if(r != null) {
            Long minus = suf.get(f.higher(max));
            if(minus == null) minus = 0L;

            sums.add(suf.get(r) - minus);
            solve(r, max, pref, suf, f, sums);
        }
    }

