int nextInt() {
			try {

				boolean negative = false;
				int res = 0;
				int limit = -Integer.MAX_VALUE;
				int radix = 10;

				int fc = nextPrintable();
				if (fc < '0') {
					if (fc == '-') {
						negative = true;
						limit = Integer.MIN_VALUE;
					} else if (fc != '+') {
						throw new NumberFormatException();
					}
					fc = br.read();
				}
				int multmin = limit / radix;

				int ch = fc;
				do {
					int digit = ch - '0';
					if (digit < 0 || digit >= radix) {
						throw new NumberFormatException();
					}
					if (res < multmin) {
						throw new NumberFormatException();
					}
					res *= radix;
					if (res < limit + digit) {
						throw new NumberFormatException();
					}
					res -= digit;

				} while (isPrintable(ch = br.read()));

				return negative ? res : -res;
			} catch (IOException e) {
				throw new NoSuchElementException();
			}
		}

static int solve(int[]a,int b){
		TreeMap<Integer,Integer>tm=new TreeMap<>();
		b--;
		for(int i=0;i<a.length;i++) {
			if(a[i]!=0) {
				int s=i-b<0?0:i-b;
				int e=i+b;
				tm.put(s, e);
			}
		}

		int cnt=0;
		int s=0;
		int end=-1;
		boolean f=true;
		while(end<a.length-1) {
			if(tm.containsKey(end+1)) {
				s=end+1;
				end=tm.get(end+1);
			}
			else {

				if(tm.floorKey(end)==null || tm.floorKey(end)<=s) {
					f=false;
					break;
				}
				int tem=tm.floorKey(end);
				s=tem;
				end=tm.get(s);
			}
			cnt++;
		}
		if(f)return cnt;
		else return -1;

	}

