int twoPointer(char[] s, int n, int k, char not) {
		int max, l, r, hole;
		max = l = r = hole = 0;
		while (true) {
			while (r < n && hole <= k) {
				if (s[r] == not) hole++;
				if (hole > k) break;
				max = Math.max(max, r - l + 1);
				r++;
			}
			while (l <= r && hole > k) {
				if (s[l++] == not) hole--;
			}
			if (r == n || r == n - 1) break;
			r++;
		}
		return max;
	}

