public void solve(FastScanner br, PrintWriter pw) throws IOException {
			long MOD = (long)1e9+7;
			String s = br.nextToken();
			int N = s.length();

			long[][] dp = new long[N][5];

			char f = s.charAt(0);

			if(f == '0') {
				dp[0][0] = 1;
			}

			else if(f == '1') {
				dp[0][2] = 1;
			}
			else if(f == '*') {
				dp[0][4] = 1;
			}
			else if(f == '?') {

			for(int i = 0 ; i < 5; i++) {
				if(i == 1 || i == 3) {
					continue;
				}


				dp[0][i] = 1;
			}
			}

			for(int i = 1; i < N; i++) {
				if(s.charAt(i) == '0') {
					dp[i][0] = (dp[i-1][1] + dp[i-1][0])%MOD;
				}
				else if(s.charAt(i) == '1') {
					dp[i][1] = dp[i-1][4]%MOD;
					dp[i][2] = (dp[i-1][1] + dp[i-1][0])%MOD;
				}
				else if(s.charAt(i) == '2') {
					dp[i][3] = dp[i-1][4]%MOD;
				}
				else if(s.charAt(i) == '*') {
					dp[i][4] = (((dp[i-1][2] + dp[i-1][3] )%MOD) + dp[i-1][4])%MOD;
				}
				else if(s.charAt(i) == '?') {
					dp[i][0] = dp[i-1][1] + dp[i-1][0];
					dp[i][0]%= MOD;
					dp[i][1] = dp[i-1][4];
					dp[i][1]%= MOD;
					dp[i][2] = dp[i-1][1] + dp[i-1][0];
					dp[i][2]%= MOD;
					dp[i][3] = dp[i-1][4];
					dp[i][3]%= MOD;
					dp[i][4] = dp[i-1][2] + dp[i-1][3] + dp[i-1][4];
					dp[i][4]%= MOD;

				}
			}
			int ans = 0;


			for(int i = 0; i < 5; i++) {
				if(i == 2 || i == 3) {
					continue;
				}
				ans += dp[N-1][i];
				ans %= MOD;	
			}

			pw.println(ans);



			pw.close();
		}

