public static int countDistance(String s) {
        int[] letterIndex = new int[26];
        for(int i=0; i<s.length(); i++) {
            int ind = (int)s.charAt(i) - (int)('a');
            letterIndex[ind] = i+1;
        }
        int[] swapArr = new int[s.length()];
        int j = 0;
        for(int i=0; i<26; i++) {
            if(letterIndex[i] > 0) {
                swapArr[j] = letterIndex[i] - 1;
                j++;
            }
        }
        int swaps = 0;
        for(int i=0; i<swapArr.length; i++) {
            if(swapArr[i] != i) {
                swaps += swapArr[i] - i;
                int[] newSwapArr = new int[swapArr.length];
                for(int k=0; k<swapArr.length; k++) {
                    if(k <= i) {
                        newSwapArr[k] = k;
                    } else if (swapArr[k] <= swapArr[i]) {
                        newSwapArr[k] = swapArr[k] + 1;
                    } else {
                        newSwapArr[k] = swapArr[k];
                    }
                }
                swapArr = newSwapArr;
            }
        }
        return swaps;
    }

