private static int BFS(int n, int m, ArrayList<ArrayList<Integer>> graph, int[] vArray)
	{
		boolean[] visited = new boolean[n + 1];
		LinkedList<Integer> q = new LinkedList<Integer>();

		for(int i = 1; i <= n; i++)
		{
			visited[i] = false;
		}

		q.add(1);
		visited[1] = true;
		int result = 0;

		while(!q.isEmpty())
		{
			int temp = q.poll();

			if(temp != 1 && graph.get(temp).size() == 1)
			{
				result++;
				continue;
			}

			for(int i = 0; i < graph.get(temp).size(); i++)
			{					
				int value = graph.get(temp).get(i);
				if(vArray[temp] + vArray[value] <= m && visited[value] == false)
				{
					q.add(value);
					visited[value] = true;

					if(vArray[temp] > 0 && vArray[value] > 0)
					{
						vArray[value] = vArray[temp] + vArray[value];
					}
				}
			}
		}

		return result;
	}

static boolean ab(int i,HashSet<Integer> hs,int n,int prev)
	{
		if(i==n)
			return true;
		int cur=2;
		while(i<4*n)
		{
			if(prev==-1)
			{
				hs.add(cur);
				if(ab(i+1, hs, n, cur))
				{

					string=cur+" "+string;
					return true;
				}
				else
					hs.remove(hs.size()-1);
			}
			else {
				if(!hs.contains(cur)&&gcd(cur, prev)>1)
				{
					hs.add(cur);
					Iterator<Integer> iterator=hs.iterator();
					int flag=0;
					while(iterator.hasNext())
					{
						int x=iterator.next();
						if(x%cur==0||cur%x==0)
						{
							flag=1;
							break;
						}
					}

					if(flag==0&&ab(i+1, hs, n, cur))
					{
					string=cur+" "+string;
					return true;
					}
					hs.remove(hs.size()-1);
				}

			}
			cur+=2;
		}
		return false;
	}

