public int rec(int mx, int my, int t) {
		if (!valid(mx, my, t)) {
			return 0;
		}
		if (state[mx][my][t] == -1) {
			if (t % 2 == 1) {
				state[mx][my][t] = rec(mx, my, t + 1);
			} else {
				state[mx][my][t] = 0;
				for (int i = 0 ;i < 9; ++i) {
					int new_x = mx + dx[i];
					int new_y = my + dy[i];
					if (rec(new_x, new_y, t + 1) == 1) {
						state[mx][my][t] = 1;
						break;
					}
				}
			}
		}
		return state[mx][my][t];
	}

