private static void solve(Scanner scan, PrintWriter pw) {
        int n = scan.nextInt();
        scan.nextLine();

        boolean[] ruledOut = new boolean[26];
        boolean[] tmp = new boolean[26];
        int numRemained= 26;

        int q = 0;
        for(; q < n-1 && numRemained > 1; q++) {
            Arrays.fill(tmp, false);

            String[] line = scan.nextLine().split(" ");
            String cmd = line[0], content = line[1];

            if(cmd.equals(".")) {
                for(int j = 0; j < content.length(); j++) {
                    int idx = content.charAt(j)-'a';
                    if(!ruledOut[idx]) {
                        ruledOut[idx] = true;
                        numRemained--;
                    }
                }
            }

            else if(cmd.equals("!")) {
                for(int j = 0; j < content.length(); j++) {
                    int idx = content.charAt(j)-'a';
                    tmp[idx] = true;
                }

                for(int j = 0; j < 26; j++) {
                    if(!ruledOut[j] && !tmp[j]) {
                        numRemained--;
                        ruledOut[j] = true;
                    }
                }
            }

            else if(cmd.equals("?")) {
                int idx = content.charAt(0) - 'a';
                if(!ruledOut[idx]) {
                    ruledOut[idx] = true;
                    numRemained--;
                }
            }
        }

        int ans = 0;

        for(; q < n-1; q++) {
            String line = scan.nextLine();
            if(line.startsWith("!") || line.startsWith("?"))
                ans++;
        }

        scan.nextLine();

        System.out.println(ans);
