        int count = 0;
        if(v1.colors.size() > 30){
            int[] colors1 = v1.getColors();
            int[] colors2 = v2.getColors();
            for(int i = Math.min(colors1.length, colors2.length) - 1; i >= 0; --i){
                count += counts[colors1[i] & colors2[i]];
            }
        } else {
            for (int i : v1.colors) {
                if (v2.colors.contains(i)) ++count;
            }
        }
        return count;
