void solve() {
        int n = in.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) a[i] = in.nextInt();

        List<Segment> segments = new ArrayList<>();
        for (int l = 0, r = 0; l < n; ) {
            while (r < n && a[r] == a[l]) r++;
            segments.add(new Segment(l, r, a[l], r - l));
            l = r;
        }

        if (segments.size() <= 2) {
            out.println(segments.size());
            return;
        }

        segments.get(0).next = segments.get(1);
        segments.get(segments.size() - 1).prev = segments.get(segments.size() - 2);
        for (int i = 1; i < segments.size() - 1; i++) {
            segments.get(i).prev = segments.get(i - 1);
            segments.get(i).next = segments.get(i + 1);
        }

        TreeSet<Segment> set = new TreeSet<>();
        for (Segment seg : segments) set.add(seg);

        int ans = 0;
        while (!set.isEmpty()) {
            ans++;
            Segment seg = set.pollFirst();
            if (seg.prev == null && seg.next == null) break;
            if (seg.prev == null) {
                seg.next.prev = null;
            } else if (seg.next == null) {
                seg.prev.next = null;
            } else {
                if (seg.prev.x != seg.next.x) {
                    seg.prev.next = seg.next;
                    seg.next.prev = seg.prev;
                } else {
                    Segment left = seg.prev.prev;
                    Segment right = seg.next.next;
                    set.remove(seg.prev);
                    set.remove(seg.next);
                    Segment merged = new Segment(seg.prev.l, seg.next.r, seg.prev.x, seg.prev.sz + seg.next.sz);
                    merged.prev = left;
                    if (left != null) left.next = merged;
                    merged.next = right;
                    if (right != null) right.prev = merged;
                    set.add(merged);
                }
            }
        }
        out.println(ans);
    }

