public Node insert(Node node) {
            Node result = this;
            if (node.value < this.value) {
                if (this.left == null) {
                    node.parent = this;
                    this.left = node;
                } else {
                    this.left = this.left.insert(node);
                }
                if (this.left.height >
                        ((this.right == null) ? 0 : this.right.height) + 1) {
                    result = this.left;
                    this.left = result.right;
                    if (this.left != null) {
                        this.left.parent = this;
                    }
                    result.right = this;
                    result.parent = this.parent;
                    this.parent = result;
                    this.refresh();
                }
            } else {
                if (this.right == null) {
                    node.parent = this;
                    this.right = node;
                } else {
                    this.right = this.right.insert(node);
                }
                if (this.right.height >
                        ((this.left == null) ? 0 : this.left.height) + 1) {
                    result = this.right;
                    this.right = result.left;
                    if (this.right != null) {
                        this.right.parent = this;
                    }
                    result.left = this;
                    result.parent = this.parent;
                    this.parent = result;
                    this.refresh();
                }
            }
            result.refresh();
            return result;
        }

