        char ss[] = s.toCharArray();
        char tt[] = t.toCharArray();
        for (int i = 0; i < n; i++) {
            if (ss[i] == '1' && tt[i] == '1') {
                col3++;
            } else {
                if (ss[i] == '1' && tt[i] == '0') {
                    col1++;
                }
                if (tt[i] == '1' && ss[i] == '0') {
                    col2++;
                }
            }
        }
        int res = 1;
        int sum1 = 0;
        int sum2 = 0;
        if (col3 % 2 == 1) {
            res = 2;
            sum1++;
        } else {
            res = 1;
        }
        while (col1 != 0 || col2 != 0) {
            if (res == 1) {
                if (col1 == 0) {
                    break;
                }
                col1--;
                sum1++;
                res = 2;
            } else {
                if (col2 == 0) {
                    break;
                }
                sum2++;
                col2--;
                res = 1;
            }
        }
        if (res == 1 && col2 > 0) {
            col2--;
        }
        sum1 += col1;
        sum2 += col2;
        if (sum1 == sum2) {
