			nums[i] = next;
			if(i == 0) {
				counter ++;
				fout.append(next + 1).append(" ");
			}
			else {

				int pathCost = i - pointer;
				int minCost = nums[pointer] == next? 0 : paths.get(nums[pointer]).get(next);

				if(pathCost > minCost) {

					counter ++;
					fout.append(nums[i - 1] + 1).append(" ");
					pointer = i - 1;
				}
			}
		}
		counter ++;
		fout.append(nums[m - 1] + 1);
		System.out.println(counter + "\n" + fout);
	}

static int[] BinarySearch(int[] arr,int x,int l,int r,int lb,int rb){
		int[] result;
		if(x<arr[0]){
			int[] re={-1,-1,0};
			return re;
		}
		if(x>arr[arr.length-1]){
			int[] re={-1,arr.length-1,-1};
			return re;
		}
		if(l>r){
			if(lb==-1){
				lb=r;
			}
			if(rb==-1){
				rb=l;
			}
			int[] re={-1,lb,rb};
			return re;
		}
		if(arr[(l+r)/2]==x){
			if(lb==-1){
				lb=(l+r)/2;
			}
			if(rb==-1){
				rb=(l+r)/2;
			}
			int[] re={(l+r)/2,lb,rb};
			return re;
		}
		else if(arr[(l+r)/2]>x){
			rb=(l+r)/2;
			result=BinarySearch(arr,x,l,rb-1,lb,rb);
		}
		else{
			lb=(l+r)/2;
			result=BinarySearch(arr,x,lb+1,r,lb,rb);
		}
		return result;
	}

