public static int twopointers(int outconsider, int[] arr, int[][] prefixArr) {
		int lp = 0;
		while(arr[lp] != outconsider) {
			if(lp == arr.length-1) {
				return 0;
			}
			lp++;
		}
		int rp = arr.length-1;
		while(arr[rp] != outconsider) {
			if(rp == 0) {
				return 0;
			}
			rp--;
		}
		int bestans = 1;
		int csize = 2;

		while(lp < rp) {
			int MR = maxRangeQuery(prefixArr, lp,rp);
			if(MR >= 0) {
				bestans = Math.max(MR + csize,bestans);
			}
			csize += 2;
			lp++;
			while(arr[lp] != outconsider) {
				if(lp == arr.length-1) {
					return bestans;
				}
				lp++;
			}
			rp--;
			while(arr[rp] != outconsider) {
				if(rp == 0) {
					return bestans;
				}
				rp--;
			}


		}
		return bestans;
	}

