public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    int [] a = new int[2 * n - 1];
    int [] b = new int[2 * n - 1];
    int howManyPositive = 0;
    for (int i = 0; i < a.length; i++) {
      a[i] = in.nextInt();
      if ( a[i] > 0 ){
        ++howManyPositive;
      }
      b[i] = Math.abs(a[i]);
    }

    Arrays.sort(b);

    HashSet<Integer> visited = new HashSet<Integer>();
    int currentPositives = howManyPositive;

    visited.add(currentPositives);
    LinkedList<Integer> queue = new LinkedList<Integer>();
    queue.add(currentPositives);

    int ans = currentPositives;
    int total = 2 * n - 1;
    while ( !queue.isEmpty() ){
      currentPositives = queue.removeFirst();
      ans = Math.max(ans, currentPositives);

      for (int action = 0; action <= n; action++) {
        int antiAction = n - action;
        int negatives = total - currentPositives;
        if ( antiAction <= currentPositives && action <= negatives ){
          int next = currentPositives - antiAction + action;
          if ( !visited.contains(next) ){
            visited.add(next);
            queue.add(next);
          }
        }

      }


    }

    int sum = 0;
    for (int i = 0; i < ans; i++) {
      sum += b[b.length - 1 - i];
    }
    for (int i = ans; i < b.length; i++) {
      sum -= b[b.length - 1 - i];
    }




    out.println(sum);
  }

