			graph[n2].add(new int[] {n1,i+1});
		}
		HashSet<Integer> ret=new HashSet<>();
		int[] vis=new int[n];
		LinkedList<int[]> queue=new LinkedList<>();
		Arrays.fill(vis, -1);
		for(int node:set) {
			vis[node]=node;
			queue.add(new int[] {node,node,0});
		}
		while(queue.size()>0) {
			int len=queue.size();
			while(len-->0) {
				int[] q=queue.poll();
				int node=q[0];
				int root=q[1];
				int dis=q[2];
				for(int[] nn:graph[node]) {
					if(vis[nn[0]]==root)continue;
					if(vis[nn[0]]!=-1) {
						ret.add(nn[1]);
					}else {
						if(dis==d) {
							ret.add(nn[1]);
						}else {
							vis[nn[0]]=root;
							queue.add(new int[] {nn[0],root,dis+1});
						}
					}
				}
			}
		}
		out.println(set.size()-1);
		for(int r:ret) {
			out.print(r+" ");
		}
	}

