private void dfs(int v, int par, int[] sum, Graph<Edge> g, int n, TreeSet<Pair<Integer,Integer>> ans) {
        sum[v] = 1;
        ArrayList<Integer> child=new ArrayList<Integer>();
        for (Edge edge : g.adjacentList(v)) {
            if (edge.to != par) {
                dfs(edge.to,v,sum,g,n,ans);
                sum[v] += sum[edge.to];
                child.add(sum[edge.to]);
            }
        }
        child.add(n - sum[v]);
        boolean []can=new boolean[n];
        can[0]=true;
        for (int x : child) {
            for (int i = n-1; i >= 0; --i) {
                if (can[i] && i + x <= n - 1) {
                    can[i + x] = true;
                }
            }
        }
        for (int i = 1; i < n-1; ++i) {
            int r = n - 1 - i;
            if (can[i]) {
                ans.add(new Pair<Integer, Integer>(i, r));
                ans.add(new Pair<Integer, Integer>(r, i));
            }
        }

    }

