        int n = nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = nextInt();
        }
        int[] dp = new int[n];
        int[] max = new int[n];
        int[] left = new int[n];
        Stack<Integer> g = new Stack<Integer>();
        dp[0] = 1;
        max[0] = a[0];
        left[0] = 0;
        g.add(0);
        RmqSparseTable sparse = new RmqSparseTable(a);

        for (int i = 1; i < n; i++) {
            if (max[i - 1] <= a[i]) {
                dp[i] = dp[i - 1] + 1;

                g.add(i);
            } else {
                int l = -1;
                int r = i - 1;
                while (r - l > 1) {
                    int m = (l + r) / 2;
                    if (max[m] > a[i]) {
                        r = m;
                    } else {
                        l = m;
                    }
                }
                while (g.peek() > r) {
                    g.pop();
                }
                int maxx = (Integer) g.peek();
                if (maxx == 0) {
                    dp[i] = 1;
                } else {
                    dp[i] = dp[maxx - 1] + 1;
                }
            }
            max[i] = Math.max(a[i], max[i - 1]);
        }
        out.println(dp[n - 1]);
    }

