                        long low = L * L - dx * dx;
                        long high = R * R - dx * dx;
                        if (low < 0)
                                low = 0;
                        if (high < 0)
                                continue;
                        long left = (int)Math.sqrt(low);
                        long right = (int)Math.sqrt(high);
                        while (left > 0 && left * left + dx * dx >= L * L)
                                left--;
                        while (left * left + dx * dx < L * L)
                                left++;
                        left--;
                        while (right > 0 && right * right + dx * dx >= R * R)
