public static void sort(int[] arr) {
            int n = arr.length, mid, h, s, l, i, j, k;
            int[] res = new int[n];
            n--;
            for (s = 1; s <= n; s <<= 1) {
                for (l = 0; l < n; l += (s << 1)) {
                    h = Math.min(l + (s << 1) - 1, n);
                    mid = Math.min(l + s - 1, n);
                    i = l;
                    j = mid + 1;
                    k = l;
                    while (i <= mid && j <= h) res[k++] = (arr[i] <= arr[j] ? arr[i++] : arr[j++]);
                    while (i <= mid) res[k++] = arr[i++];
                    while (j <= h) res[k++] = arr[j++];
                    for (k = l; k <= h; k++) arr[k] = res[k];
                }
            }

        }

private long rec(int l1, int r1, int l2, int r2, int len) {
        if (len == 0) return 0;
        if (l1 > r1 || l2 > r2) return 0;
        if (r1 - l1 + 1 == len) {
            return r2 - l2 + 1;
        }
        if (r2 - l2 + 1 == len) {
            return r1 - l1 + 1;
        }
        int center = (len / 2) + 1;
        if (r1 < center && r2 < center) return rec(l1, r1, l2, r2, len / 2);
        if (l1 > center && l2 > center) return rec(l1 - center, r1 - center, l2 - center, r2 - center, len / 2);
        if (r1 < center && l2 > center) {
            return rec(l1, r1, l2 - center, r2 - center, len / 2);
        }
        if (r2 < center && l1 > center) {
            return rec(l1 - center, r1 - center, l2, r2, len / 2);
        }
        if (l1 <= center && r1 >= center) {
            if (l2 <= center && r2 >= center) {
                long max = 0;
                if (center - l1 >= r1 - center) {
                    max = rec(l1, center - 1, l2, r2, len);
                } else {
                    max = Math.max(max, rec(center + 1, r1, l2, r2, len));
                }
                int le = Math.max(l1, l2);
                int ri = Math.min(r1, r2);
                max = Math.max(max, ri - le + 1);
                return max;
            } else {
                return Math.max(rec(l1, center-1, l2, r2, len), rec(center + 1, r1, l2, r2, len));





            }
        } else if (l2 <= center && r2 >= center) {
            return rec(l2, r2, l1, r1, len);
        }
        throw new AssertionError("!");
    }

boolean empty(long pos) {
		if (k == n) return false;
		if (k == 0) return true; 
		long free = n - k;
		if (free <= n / 2) {
			if (pos % 2 == 1 && (pos + 1) / 2 <= free) {
				return true;
			} else
				return false;
		}
		long a = n - 2 * k + 1;
		if (a % 2 == 0 && a < free) a++;
		if (pos <= a) return true;
		if ((pos - a) % 2 == 0 && (pos - a) / 2 <= free - a) return true;
		return false;
	}

