            boolean isVisX1 = false, isVisX2 = false;
            int dis = 0;
            while (true) {
                if (p == x1)
                    isVisX1 = true;
                if (p == x2)
                    if (isVisX1)
                        isVisX2 = true;
                if (isVisX1 && isVisX2)
                    return dis * t1;

                p += d;
                if (p < 0) {
                    p = 1;
                    d = 1;
                }
                if (p > s) {
                    p = s - 1;
                    d = -1;
                }
                dis++;
            }
        }

