public static long getClosestK(long[] a, long x) {

    int low = 0;
    int high = a.length - 1;

    while (low <= high) {
        int mid = (low + high) / 2;


        if (mid == 0) {
            if (a.length == 1) {
                return a[0];
            }

            return Math.min(Math.abs(a[0] - x), Math.abs(a[1] - x)) + x;
        }



        if (mid == a.length - 1) {
            return a[a.length - 1];
        }


        if (a[mid] == x || a[mid + 1] == x) {
            return x;
        }



        if (a[mid] < x  && a[mid + 1] > x) {
            return Math.min(Math.abs(a[mid] - x), Math.abs(a[mid + 1] - x)) + x;
        }


        if (a[mid] < x) {
            low = mid + 1;
        } else { 
            high = mid;
        }
    }

    throw new IllegalArgumentException("The array cannot be empty");
}

public static int get(int index, int sm, int lr) {
        if (index == DP.length)
            return 0;
        if (DP[index][sm][lr] != -1)
            return DP[index][sm][lr];

        boolean canZ = true;
        if (l.charAt(index) == '1' && lr == 0)
            canZ = false;
        boolean canO = true;
        if (r.charAt(index) == '0' && sm == 0)
            canO = false;
        int ansZ = -1;
        if (canZ) {
            int newSm = sm == 1 || r.charAt(index) == '1' ? 1 : 0;
            ansZ = get(index + 1, newSm, lr);
        }
        int ansO = -1;
        if (canO) {
            int newLr = lr == 1 || l.charAt(index) == '0' ? 1 : 0;
            ansO = 1 + get(index + 1, sm, newLr);
        }
        if (ansZ >= ansO)
            next[index][sm][lr] = 0;
        else
            next[index][sm][lr] = 1;
        return DP[index][sm][lr] = Math.max(ansO, ansZ);
    }

