		cdp[0 * M1 + 0 * M2 + 0] = 1L;
		long t = x;
		for (int l = 0; l < MAXL && t > 0L; l++, t /= 10L) {
			int cd = (int) (t % 10L);
			for (int r = 0; r < LCM; r++)
				for (int m = 0; m < MAXM; m++) {
					if (dp[l * M1 + r * M2 + m] != 0L)
						for (int d = 0; d < cd; d++)
							cdp[(l + 1) * M1 + nextRest[(l + 1) * R1 + r * R2 + d] * M2 + nextInd[(m << 4) | d]] += dp[l * M1 + r * M2 + m];
					if (cdp[l * M1 + r * M2 + m] != 0L)
						cdp[(l + 1) * M1 + nextRest[(l + 1) * R1 + r * R2 + cd] * M2 + nextInd[(m << 4) | cd]] += cdp[l * M1 + r * M2 + m];
				}
		}
		long ret = 0L;
		int len = len(x);
		for (int r = 0; r < LCM; r++)
			for (int m = 0; m < MAXM; m++)
				if (m == 0 || r % lcm[m] == 0)
					ret += cdp[len * M1 + r * M2 + m];
		return ret;
	}

