long findIT(int index, int odd, int even, int parity) {
            if (odd < 0) return Integer.MAX_VALUE / 2;
            if (even < 0) return Integer.MAX_VALUE / 2;
            if (index == n) return 0;

            if (dp[index][odd][even][parity] != -1) return dp[index][odd][even][parity];
            if (arr[index] != 0) {
                int pp = (arr[index] % 2) == parity ? 0 : 1;
                return dp[index][odd][even][parity] = pp + findIT(index + 1, odd, even, arr[index] % 2);
            } else {
                long ans = Integer.MAX_VALUE / 2;
                {
                    int pp = (0) == parity ? 0 : 1;
                    ans = Math.min(ans, pp + findIT(index + 1, odd, even - 1, 0));
                }
                {
                    int pp = (1) == parity ? 0 : 1;
                    ans = Math.min(ans, pp + findIT(index + 1, odd - 1, even, 1));
                }
                return dp[index][odd][even][parity] = ans;
            }

        }

