            int s = in.nextInt();
            int t = in.nextInt();
            buses[i] = new Bus(s, t);
            set.add(s);
            set.add(t);
        }

        int index = 0;
        Map<Integer,Integer> posMap = new HashMap<Integer,Integer>();
        for (int p:set) {
            posMap.put(p, index);
            index++;
        }

        for (Bus b:buses) {
            b.s = posMap.get(b.s);
            b.t = posMap.get(b.t);
        }

        Arrays.sort(buses, new Comparator<Bus> () {
            public int compare(Bus a, Bus b) {
                return a.t-b.t;
            }
        });

        int[] dp = new int[index];
        int[] sum = new int[index+1];
        dp[0] = 1;
        sum[1] = 1;
        for (int i=1;i<index;i++) {
            int j = Arrays.binarySearch(buses, new Bus(-1,i), new Comparator<Bus>() {
                public int compare(Bus a, Bus b) {
                    return a.t-b.t;
                }
            });
            if (j>=0) {
                while (j!=0&&buses[j-1].t==i) 
                    j--;
                while (j<m&&buses[j].t==i) {
                    dp[i] = add(dp[i], sum[i]-sum[buses[j].s]);
                    j++;
                }
            }
            sum[i+1] = add(sum[i],dp[i]);

        }

        System.out.println(dp[index-1]);
    }

public static void move(int s_x, int s_y, int d_x, int d_y) {
		if(s_x == d_x && s_y == d_y) {
			return;
		}
		else if (s_x > d_x && s_y < d_y) {

			counter++;
			answer.append("LU\n");
			move(s_x-1, s_y+1, d_x, d_y);
		}
		else if (s_x > d_x && s_y > d_y) {

			counter++;
			answer.append("LD\n");
			move(s_x-1, s_y-1, d_x, d_y);
		}
		else if (s_x < d_x && s_y < d_y) {

			counter++;
			answer.append("RU\n");
			move(s_x+1, s_y+1, d_x, d_y);
		}
		else if (s_x < d_x && s_y > d_y) {

			counter++;
			answer.append("RD\n");
			move(s_x+1, s_y-1, d_x, d_y);
		}
		else if (s_x == d_x && s_y < d_y) {

			counter++;
			answer.append("U\n");
			move(s_x, s_y+1, d_x, d_y);
		}
		else if (s_x == d_x && s_y > d_y) {

			counter++;
			answer.append("D\n");
			move(s_x, s_y-1, d_x, d_y);
		}
		else if (s_x < d_x && s_y == d_y) {

			counter++;
			answer.append("R\n");
			move(s_x+1, s_y, d_x, d_y);
		}
		else if (s_x > d_x && s_y == d_y) {

			counter++;
			answer.append("L\n");
			move(s_x-1, s_y, d_x, d_y);
		}
	}

