            }
            if (obj == null)
            {
                return false;
            }
            if (getClass() != obj.getClass())
            {
                return false;
            }
            final Pair<?, ?> other = (Pair<?, ?>) obj;
            if (!Objects.equals(this.first, other.first))
            {
                return false;
            }
            if (!Objects.equals(this.second, other.second))
            {
                return false;
            }
            return true;
        }

