			i++;
		}


		if (company.charAt(i) == '.') {
			enter = false;
		}

		company = company.substring(i + 1);

		if (noParents.containsKey(boss))
		{
			int num = noParents.get(boss);
			noParents.remove(boss);
			num++;
			counter = counter+num;
			noParents.put(boss, num);
		}
		else
		{
			noParents.put(boss, 0);
		}

		for (; i < company.length() && enter;){
			if(company.charAt(0) == ',')
				company = company.substring(1);
