        BigInteger x = BigInteger.ONE;

        int zeroes = 0;

        Set<Character> differentLetters = new HashSet<Character>();

        boolean firstIsLetter = false;

        if (s.charAt(0) == '?') {
            x = x.multiply(BigInteger.valueOf(9));
        }
        if (s.charAt(0) >= 'A' && s.charAt(0) <= 'Z') {
            differentLetters.add(s.charAt(0));
            firstIsLetter = true;
        }

        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) == '?') {
                zeroes++;
                continue;
            }
            if (s.charAt(i) >= 'A' && s.charAt(i) <= 'Z') {
                differentLetters.add(s.charAt(i));
            }
        }

        int d = 10;

        for (int i = 0; i < differentLetters.size(); i++) {
            x = x.multiply(BigInteger.valueOf(d--));
        }

        if (firstIsLetter) {
            x = x.divide(BigInteger.valueOf(10)).multiply(BigInteger.valueOf(9));
        }

        out.print(x);
        for (int i = 0; i < zeroes; i++) {
            out.print('0');
        }
    }

