int query( int n, int[] T, int[][] P, int[] L, int u, int v){


	    if (L[u] < L[v]){
	    	int tmp = u ;
	    	u = v ; 
	    	v = tmp;
	    }	       

	    int log = 1 ;

	    for(  ; 1 << log <= L[u]; log++);
	    log--;



	    for (int i = log; i >= 0; i--)
	    	if (L[u] - (1 << i) >= L[v])
	    		u = P[u][i];

		if( u == v )
			return u ;


		for (int i = log; i >= 0; i--)
			if (P[u][i] != -1 && P[u][i] != P[v][i]){
				u = P[u][i] ; 
				v = P[v][i];
			}

		return T[u];
	}

