private static int solve2(int n, List<Integer> numbers) {
        int[] grid = new int[n + 1];

        Arrays.fill(grid, -1);

        if (numbers.get(0) <= n) {
            grid[numbers.get(0)] = 1;
        }

        if (numbers.get(1) <= n) {
            grid[numbers.get(1)] = 1;
        }

        if (numbers.get(2) <= n) {
            grid[numbers.get(2)] = 1;
        }

        for (int i = numbers.get(0); i <= n; i++) {
            if (grid[i] == -1) {
                continue;
            }

            if (i + numbers.get(0) <= n) {
                grid[i + numbers.get(0)] = Math.max(grid[i + numbers.get(0)], grid[i] + 1);
            }

            if (i + numbers.get(1) <= n) {
                grid[i + numbers.get(1)] = Math.max(grid[i + numbers.get(1)], grid[i] + 1);
            }

            if (i + numbers.get(2) <= n) {
                grid[i + numbers.get(2)] = Math.max(grid[i + numbers.get(2)], grid[i] + 1);
            }

        }

        return grid[n];
    }

