    	 if(count > 3)
             return 0;
         if( pos == no.length() )
            return 1;
        if(dp[pos][count][isTight] != -1)
            return dp[pos][count][isTight];
        long ans = 0, upperBound = 9;
        if(isTight == 1)
            upperBound = (int)( no.charAt(pos) - '0' );
        for(int i = 0; i <= upperBound;i++){
            int flag = ( i != 0)? 1 : 0, tempTight = 0;
            if(isTight == 1 && i == upperBound)
                tempTight = 1;
            ans += getCount( pos + 1, count + flag, tempTight, dp, no);            
        }
        return dp[pos][count][isTight] = ans;
    }

