public static boolean isPrime(long n){
		if(n < 2) return false;
		if(n == 2 || n == 3) return true;
		if(n%2 == 0 || n%3 == 0) return false;
		long sqrtN = (long)Math.sqrt(n)+1;
		for(long i = 6L; i <= sqrtN; i += 6) {
			if(n%(i-1) == 0 || n%(i+1) == 0) return false;
		}
		return true;
	}

static int lca(int a, int b, int[][] lift, int[] depths, int[] ps)
{
    if(depths[a] < depths[b])
    {
        int temp = a; a = b; b = temp;
    }
    int log = 0;
    for(log = 1; (1<<log) <= depths[a]; log++);
    log--;
    for(int i = log; i >= 0; i--)
        if(depths[a] - (1<<i) >= depths[b])
            a = lift[a][i];
    if(a == b) return a;
    for(int i = log; i>=0; i--)
        if(lift[a][i] != -1 && lift[a][i] != lift[b][i])
        {
            a = lift[a][i];
            b = lift[b][i];
        }
    return ps[a];
}

static <T> int rlowerBound(List<T> ls, T x) {
		if (ls.size() == 0)
			return -1;
		if (ls.get(0) instanceof Integer) {
			return ~Collections.binarySearch(ls, x, (t1, t2) -> ((Integer) t1).compareTo((Integer) t2) <= 0 ? 1 : -1);
		} else if (ls.get(0) instanceof Long) {
			return ~Collections.binarySearch(ls, x, (t1, t2) -> ((Long) t1).compareTo((Long) t2) <= 0 ? 1 : -1);
		} else if (ls.get(0) instanceof Double) {
			return ~Collections.binarySearch(ls, x, (t1, t2) -> ((Double) t1).compareTo((Double) t2) <= 0 ? 1 : -1);
		} else {
			System.err.println(
					String.format("%s:Arey maa chudi padi hai", Thread.currentThread().getStackTrace()[1].getMethodName()));
			throw new RuntimeException();
		}
	}

private static boolean checkPossible(long x, long y, long a, long b, long dx, long dy) {


        if (dx == 0 && dy == 0) {
            return x == a && y == b;
        } else if (dx == 0) {
            return x == a && (b - y) % dy == 0 && (b - y) / dy >= 0;
        } else if (dy == 0) {
            return y == b && (a - x) % dx == 0 && (a - x) / dx >= 0;
        } else {
            return (a - x) % dx == 0 && (b - y) % dy == 0 && (a - x) / dx == (b - y) / dy && (a - x) / dx >= 0;
        }
    }

