public long readLong() {
        try {
            long r = 0;
            boolean start = false;
            boolean neg = false;
            while (true) {
                int c = br.read();
                if (c >= '0' && c <= '9') {
                    r = r * 10 + c - '0';
                    start = true;
                } else if (!start && c == '-') {
                    start = true;
                    neg = true;
                } else if (start || c == -1) return neg ? -r : r;
            }
        } catch (Exception ex) {
            return -1;
        }
    }

private static long steps(long x, long y, long m) {
		if (x >= m || y >= m) {
			return 0;
		}
		if (x <= 0 && y <= 0) {
			return -1;
		}
		if (x < y) {
			long t = x;
			x = y;
			y = t;
		}
		long steps = 0;
		if (y < 0) {
			long stepsToMakeNonNegative = (Math.abs(y) + x - 1) / x;
			y += stepsToMakeNonNegative * x;
			steps += stepsToMakeNonNegative;
		}
		while (x < m && y < m) {
			long nx = max(x, y);
			long ny = x + y;

			x = nx;
			y = ny;
			++steps;
		}
		return steps;
	}

