            if(i==0) prev=arr[i];
            else prev=arr[i-1];
            if(i==n-1) next =arr[i];
            else next=arr[i+1];
            long t= sum-Math.abs(arr[i]-prev)-Math.abs(arr[i]-next);
            if(i!=0 && i!=n-1) t+=Math.abs(prev-next);
            res=Math.min(res,t);
        }
        out.println(res);
    }

