static long dp(int i, int isequal, int nonzeros) {
        if (nonzeros > 3) return 0;
        if (i == 19)
            return 1;
        if (memo[i][isequal][nonzeros] != -1)
            return memo[i][isequal][nonzeros];
        long cnt = 0;
        int digit = n[i];
        for (int j = 0; j < 10; j++) {
            if (isequal == 1 && j == digit) {
                cnt += dp(i + 1, 1, (j == 0) ? nonzeros : nonzeros + 1);
                continue;
            }
            if (isequal == 0)
                cnt += dp(i + 1, isequal, (j == 0) ? nonzeros : nonzeros + 1);
            if (isequal == 1 && j < digit)
                cnt += dp(i + 1, 0, (j == 0) ? nonzeros : nonzeros + 1);
        }
        return memo[i][isequal][nonzeros] = cnt;
    }

