static boolean check(int x, int y, int from, int to) {
		int fromj = getj(from, x, y); int fromi = (from-fromj)/y+1;
		assert fromi<=x;
		int toj = getj(to, x, y); int toi = (to-toj)/y+1;
		assert toi<=x;
		boolean ret = false;


		if(fromi<x) {
			ret |= (fromi+1==toi && fromj==toj);
		}
		if(fromj<y) {
			ret |= (fromi==toi && fromj+1==toj);
		}
		if(fromi>1) {
			ret |= (fromi-1==toi&&fromj==toj);
		}
		if(fromj>1){
			ret |= (fromi==toi && fromj-1==toj); 
		}
		return ret;
	}

private RMQ getNode (int from, int to) {
			assert(from >= this.from && to <= this.to && from < to);
			if (from == this.from && to == this.to)
				return this;
			RMQ r = null, s = null;
			if (from < m)
				r = L.getNode(from, min(to, m));
			if (m < to)
				s = R.getNode(max(from, m), to);
			if (r == null)
				return s;
			else if (s == null)
				return r;
			else if (r.X <= s.X)
				return r;
			else
				return s;
		}

