static boolean jikken() {
        boolean[] tree = new boolean[N+1];
        for (int i = 1; i <= N; i++) {
            if( !tree[i-1] ) {
                tree[i] = true;
                continue;
            }

            if( i >= 2 && !tree[i-2] ) {
                tree[i] = true;
                continue;
            }

            if( i >= K && !tree[i-K] ) {
                tree[i] = true;
            } else {
                tree[i] = false;
            }
        }

        int[] hoge = new int[N+1];
        for (int i = 0; i <= N; i++) {
            hoge[i] = tree[i] ? 1 : 0;
        }
        debug(hoge);
        return tree[N];
    }

