private static int[][] computeSuffixArray(String s) {
        int n = s.length();
        char[] A = s.toCharArray();
        Entry[] M = new Entry[n];
        for (int i = 0; i < n; i++)
            M[i] = new Entry();


        int[][] P = new int[MAXLG][n];
        for (int i = 0; i < n; i++)
            P[0][i] = (int) A[i];

        int level = 1;
        for (int skip = 1; skip < n; level++, skip *= 2) {
            for (int i = 0; i < n; i++) {
                M[i].nr[0] = P[level - 1][i];
                M[i].nr[1] = (i + skip < n) 
                    ? P[level - 1][i + skip] : -1000;
                M[i].p = i;
            }
            Arrays.sort(M);

            for (int i = 0; i < n; i++) {
                P[level][M[i].p] = (i > 0 
                    && M[i].nr[0] == M[i - 1].nr[0] 
                    && M[i].nr[1] == M[i - 1].nr[1]) 
                    ? P[level][M[i - 1].p] : i;
            }
        }

        return Arrays.copyOf(P, level);
    }

