public void solve(int testNumber, Scanner in, PrintWriter out) {
        long days = in.nextInt();
        long entries = in.nextInt();
        LinkedHashMap<Long, Long> dayToHeightMap = new LinkedHashMap<>();
        for (int i=0; i < entries; i++){
            long day = in.nextInt();
            long height = in.nextInt();
            dayToHeightMap.put(day, height);
        }

        List<Interval> intervals = new ArrayList<>();
        Iterator<Map.Entry<Long, Long>> iterator = dayToHeightMap.entrySet().iterator();
        long prevDay = iterator.next().getKey();
        while(iterator.hasNext()){
            long currDay = iterator.next().getKey();
            Interval i = new Interval(prevDay,currDay);
            prevDay = currDay;
            intervals.add(i);
        }

        if(intervals.size() == 0){
            out.print(Math.max(dayToHeightMap.get(prevDay) + prevDay - 1, dayToHeightMap.get(prevDay) + days-prevDay));
            return;
        }


        long maxHeight = -1;
        if(intervals.get(0).start != 1){
            maxHeight = dayToHeightMap.get(intervals.get(0).start) + (intervals.get(0).start - 1);
        }

        long endDay = intervals.get(intervals.size() - 1).end;
        if (endDay != days)
            maxHeight = Math.max(maxHeight, dayToHeightMap.get(endDay) + (days- endDay));

        for (Interval interval : intervals) {
            long heightStart =  dayToHeightMap.get(interval.start);
            long heightEnd = dayToHeightMap.get(interval.end);
            long diff = Math.abs(heightStart - heightEnd);
            long slots = (interval.end - interval.start -1);
            if (diff > slots + 1) {
                out.println("IMPOSSIBLE");
                return;
            }
            while (diff < slots) {
                diff++;
                slots--;
            }

            maxHeight = Math.max(maxHeight, Math.min(heightEnd, heightStart) + diff);
        }

        out.print(maxHeight);

    }

