        int k = nextInt();
        char[] s = next().toCharArray();
        int[] freq = new int[26];
        for (char c : s) {
            freq[c - 'a'] += k;
        }
        class SegmentTree {
            int q;
            int[] a;
            SegmentTree(int n) {
                q = 1;
                while(q <= n) {
                    q *= 2;
                }
                a = new int[2 * q];
            }
            void increment(int i) {
                for(i += q; i > 0; i /= 2) {
                    a[i]++;
                }
            }
            int getZeroPos(int k, int seg, int l, int r) {
                if(r - l == 1) {
                    return l;
                }
                int med = l + r >> 1;
                if(med - l - a[seg * 2] >= k) {
                    return getZeroPos(k, seg * 2, l, med);
                } else {
                    return getZeroPos(k - (med - l - a[seg * 2]), seg * 2 + 1, med, r);
                }
            }
            int getZeroPos(int k) {
                return getZeroPos(k, 1, 0, q);
            }
        }
        SegmentTree[] segmentTrees = new SegmentTree[26];
        for(int i = 0; i < 26; i++) {
            segmentTrees[i] = new SegmentTree(freq[i]);
        }
        int q = nextInt();
        for(int i = 0; i < q; i++) {
            int x = nextInt();
            char c = next().charAt(0);
            int zp = segmentTrees[c - 'a'].getZeroPos(x);
            segmentTrees[c - 'a'].increment(zp);
        }
        Arrays.fill(freq, 0);
        for(int i = 0; i < k; i++) {
            for (char c : s) {
                int ci = freq[c - 'a'];
                final SegmentTree st = segmentTrees[c - 'a'];
                if(st.a[ci + st.q] == 0) {
                    writer.print(c);
                }
                freq[c - 'a']++;
            }
        }
    }

private int countModified(int threadHold, Map<Integer, Integer> map) {
        int currDist = map.size();
        int tmp = (int)(Math.log(currDist) / Math.log(2));
        if (Math.pow(2, tmp) < currDist) {
            tmp += 1;
        }
        while (tmp > threadHold) {
            currDist--;
            tmp = (int)(Math.log(currDist) / Math.log(2));
            if (Math.pow(2, tmp) < currDist) {
                tmp += 1;
            }
        }

        if (currDist == map.size()) {
            return 0;
        }

        int[] sum = new int[map.size()];
        int pnt = 0;
        for (int key : map.keySet()) {
            sum[pnt] = (pnt == 0 ? 0 : sum[pnt - 1]) + map.get(key);
            pnt++;
        }

        int change = Integer.MAX_VALUE;
        int changeKeys = map.size() - currDist;
        for (int i = 0; i <= changeKeys; i++) {
            int j = changeKeys - i;

            int sub = 0;
            sub += i == 0 ? 0 : sum[ i- 1];
            sub += j == 0 ? 0 : (sum[map.size() - 1] - sum[map.size() - 1 - j]);

            change = Math.min(change, sub);
        }

        return change;
    }

