static long solve(int l,int r,int lc,int rc) throws Exception
	{

		if(l>r)
		{
			return 1;
		}

		if(l==r)
		{
			System.out.println(l);

			throw new Exception("Impossible");
		}

		if(dp[l][r][lc][rc] != -1)
		{
			return dp[l][r][lc][rc];
		}

		else
		{
			long ret=0;int curr=arr[l];

			for(int i=0;i<=1;i++)
			{
				if(i != lc)
				{
					long now = (solve(l+1,curr-1,i,2)*solve(curr+1,r,2,rc))%mod;

					ret=(ret+now)%mod;
				}

				if((curr+1<=r) || i!=rc)
				{
					long now = (solve(l+1,curr-1,2,i)*solve(curr+1,r,i,rc))%mod;

					ret=(ret+now)%mod;
				}
			}

			dp[l][r][lc][rc]=ret; return ret;
		}
	}

