private int convert(String c) {
        int r1 = 0;
        int r2 = 0;
        if(Character.isDigit(c.charAt(0)))
            r1 = c.charAt(0) - '0';
        else {
            char ch = c.charAt(0);
            if(ch == 'T') r1 = 10;
            if(ch == 'J') r1 = 11;
            if(ch == 'Q') r1 = 12;
            if(ch == 'K') r1 = 13;
            if(ch == 'A') r1 = 14;
        }
        r1 = 4 * r1;

        char ch = c.charAt(1);
        if(ch == 'D') r2 = 1;
        if(ch == 'H') r2 = 2;
        if(ch == 'C') r2 = 3;

        return r1 + r2;
    }

