	    			tempHash = ((tempHash - initial * (t.charAt(j - 1) - 'a') % P + P) * 26 + (t.charAt(j + i - 1) - 'a')) % P;
	    		} else {
	    			hash = (26 * hash + t.charAt(j + i - 1) - 'a') % P;
	    			tempHash = hash;
	    		}

	    		if(isBeg[j] && isEnd[j + i - 1] && i >= sBegLen && i >= sEndLen) {
	    			Uniques.add(tempHash);
	    		}
	    	}

	    	count += Uniques.size();
	    	initial = 26 * initial % P;

	    }

	    System.out.println(count);

	}

