        int n = s.length, m = t.length;

        int[][] lcp1 = new int[n + 1][n + 1];
        for (int i = n - 1; i >= 0; i--) {
            for (int j = n - 1; j >= 0; j--) {
                if (s[i] == s[j]) lcp1[i][j] = 1 + lcp1[i + 1][j + 1];
            }
        }

        int[] min1 = new int[n + 1];
        for (int i = 0; i < n; i++) {
            int max = 0;
            for (int j = 0; j < n; j++) {
                if (i != j) max = Math.max(max, lcp1[i][j]);
            }
            if (i + max < n) min1[i] = max + 1;
            else min1[i] = INF;
        }

        int[][] lcp2 = new int[m + 1][m + 1];
        for (int i = m - 1; i >= 0; i--) {
            for (int j = m - 1; j >= 0; j--) {
                if (t[i] == t[j]) lcp2[i][j] = 1 + lcp2[i + 1][j + 1];
            }
        }

        int[] min2 = new int[m + 1];
        for (int i = 0; i < m; i++) {
            int max = 0;
            for (int j = 0; j < m; j++) {
                if (i != j) max = Math.max(max, lcp2[i][j]);
            }
            if (i + max < m) min2[i] = max + 1;
            else min2[i] = INF;
        }

        int[][] lcp3 = new int[n + 1][m + 1];
        for (int i = n - 1; i >= 0; i--) {
            for (int j = m - 1; j >= 0; j--) {
                if (s[i] == t[j]) lcp3[i][j] = 1 + lcp3[i + 1][j + 1];
            }
        }

        int ans = INF;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int L = Math.max(min1[i], min2[j]);
                if (i + L - 1 >= n || j + L - 1 >= m || lcp3[i][j] < L) continue;
                ans = Math.min(ans, Math.min(lcp3[i][j], L));
            }
        }

