public static int find(int n, int[] a) {
        sort(a);
        int res = 0;
        boolean[] found = new boolean[n+1];
        int last = 1;
        for (int i = 0; i < n; i++) {
            if (a[i] >= 1 && a[i] <= n && !found[a[i]]) {
                found[a[i]] = true;
            }
            else {
                if (a[i] <= 2*last) return -1;
                res++;
                found[last] = true;
            }
            while (last <= n && found[last]) last++;
        }
        return res;
    }

