            "1101111".toCharArray(), "1010010".toCharArray(), "1111111".toCharArray(), "1111011".toCharArray()
    };
    int n = in.ni(), k = in.ni();
    int[][] cost = new int[n][10];
    for (int i = 0; i < n; i++) {
      char[] x = in.next().toCharArray();
      for (int digit = 0; digit < 10; digit++) {
        for (int pos = 0; pos < 7; pos++) {
          if (DIGITS[digit][pos] == '0' && x[pos] == '1') {
            cost[i][digit] = -1;
            break;
          }
          if (DIGITS[digit][pos] == '1' && x[pos] == '0') {
            cost[i][digit]++;
          }
        }
      }
    }

    boolean[][] dp = new boolean[n + 1][k + 1];
    dp[n][0] = true;
    for (
            int idx = n;
            idx > 0; idx--) {
      for (int remaining = 0; remaining <= k; remaining++) {
        if (dp[idx][remaining]) {
          for (int digit = 0; digit < 10; digit++) {
            int p = cost[idx - 1][digit];
            if (p != -1 && remaining + p <= k) {
              dp[idx - 1][remaining + p] = true;
            }
          }
        }
      }
    }
    if (!dp[0][k]) {
      out.println(-1);
    } else {
      for (int i = 0; i < n; i++) {
        int digit = -1;
        for (int d = 9; d >= 0; d--) {
          if (cost[i][d] != -1 && cost[i][d] <= k && dp[i + 1][k - cost[i][d]]) {
            k -= cost[i][d];
            digit = d;
            break;
          }
        }
        out.print(digit);
      }
    }
  }

