                    t[r][c] = '.';
                    dist[r][c] = -1;
                    int r1 = r - radius;
                    int r2 = r + radius;
                    int c1 = c - radius;
                    int c2 = c + radius;
                    if (r1 >= 0 && r2 < height && c1 >= 0 && c2 < width && getSum(r1, c1, r2, c2) == area) {
                        t[r][c] = 'X';
                        qr[qh] = r;
                        qc[qh] = c;
                        ++qh;
                        dist[r][c] = 0;
                    }
                }
            }

            while (qt < qh) {
                int r = qr[qt];
                int c = qc[qt];
                ++qt;
                if (dist[r][c] == radius) {
                    continue;
                }
                for (int dr = -1; dr <= 1; dr++) {
                    for (int dc = -1; dc <= 1; dc++) {
                        int nr = r + dr;
                        int nc = c + dc;
                        if (nr < 0 || nr >= height || nc < 0 || nc >= width) {
                            continue;
                        }
                        if (dist[nr][nc] < 0) {
                            dist[nr][nc] = 1 + dist[r][c];
                            qr[qh] = nr;
                            qc[qh] = nc;
                            ++qh;
                        }
                    }
                }
            }

            for (int r = 0; r < height; r++) {
                for (int c = 0; c < width; c++) {
                    char ch = dist[r][c] < 0 ? '.' : 'X';
                    if (ch != s[r][c]) {
                        return false;
                    }
                }
            }
            return true;
        }

