        ans++;
        while (!qu.isEmpty()) {
            int[] d = qu.pollFirst();
            int x = d[0], y = d[1], L = d[2], R = d[3];
            for (int i = 0; i < 2; i++) {
                int nx = x + dx[i], ny = y + dy[i];
                if (nx >= 0 && nx < n && ny >= 0 && ny < m && b[nx][ny] == '.' && inq[nx][ny] == 0) {
