private void solve(InputReader inp, PrintWriter out) {
            int n = inp.nextInt(), m = inp.nextInt();
            boolean[][] obs = new boolean[n][m];
            int yStart = inp.nextInt() - 1, xStart = inp.nextInt() - 1;
            int left = inp.nextInt(), right = inp.nextInt();
            for (int i = 0; i < n; i++) {
                String row = inp.next();
                for (int j = 0; j < m; j++) {
                    obs[i][j] = row.charAt(j) == '*';
                }
            }

            boolean[][] visited = new boolean[n][m];
            int res = 0;
            LinkedList<Travel> queue = new LinkedList<>();
            queue.addLast(new Travel(xStart, yStart, left, right));
            while (!queue.isEmpty()) {
                Travel t = queue.poll();
                int x = t.x, y = t.y;
                if (visited[y][x]) continue;
                visited[y][x] = true;
                res++;
                if (y - 1 >= 0 && !visited[y-1][x] && !obs[y-1][x])
                    queue.addFirst(new Travel(x, y-1, t.left, t.right));
                if (y + 1 < n && !visited[y+1][x] && !obs[y+1][x])
                    queue.addFirst(new Travel(x, y + 1, t.left, t.right));
                if (x - 1 >= 0 && t.left > 0 && !visited[y][x-1] && !obs[y][x-1])
                    queue.addLast(new Travel(x - 1, y, t.left - 1, t.right));
                if (x + 1 < m && t.right > 0 && !visited[y][x+1] && !obs[y][x+1])
                    queue.addLast(new Travel(x + 1, y, t.left, t.right - 1));
            }
            out.print(res);
        }

