        		}
        		else {
        			map.put(val, i + 1);
        			prev.put(val, i);
        		}
        	}

        	for (int x: prev.keySet()) {
        		map.put(x, Math.max(map.get(x), n - prev.get(x)));
        	}


        	int[] gaps = new int[n + 1];
        	Arrays.fill(gaps, Integer.MAX_VALUE);
