		while (h > 0 && (r > 0 || g > 0) && (r >= h || g >= h)) {
			if (r < g) {
				if (r >= h)
					r -= h;
				else g -= h;
			}

			else if (g >= h)
				g -= h;
			else r -= h;
			h -- ;
		}
		return h <= 0;
	}

