private <S extends Comparable<S>,T extends Comparable<T>> void qs(ArrayList<S> x,ArrayList<T> y,int lo,int hi) {
		if(x==null||x.size()==0||lo>=hi) {return;}
		S p=x.get(lo+(hi-lo)/2);
		T q=y.get(lo+(hi-lo)/2);
		int i=lo,j=hi;
		while (i<=j) {
			while (x.get(i).compareTo(p)<0||(x.get(i).equals(p)&&y.get(i).compareTo(q)<0)) {i++;}
			while (x.get(j).compareTo(p)>0||(x.get(j).equals(p)&&y.get(j).compareTo(q)>0)) {j--;}
			if (i<=j) {
				Utils.swap(x,i,j);
				Utils.swap(y,i,j);
				i++;j--;
			}
		}
		if (lo<j) {qs(x,y,lo,j);}
		if (hi>i) {qs(x,y,i,hi);}
	}

