            int n = in.nextInt();
            ModInt[][] dp = new ModInt[n + 1][64];
            ModInt[] tmp = new ModInt[64];
            ModInt res = new ModInt(0);

            for (int i = 0; i < 64; i++) {
                if (i == 6 || i == 9 || i == 33) {
                    dp[3][i] = new ModInt(0);
                } else {
                    dp[3][i] = new ModInt(1);
                }
            }

            for (int i = 3; i < n; i++) {
                Arrays.fill(tmp, new ModInt(0));
                for (int j = 0; j < 64; j++) {
                    for (int k = 0; k < 4; k++) {
                        if ((j / 4 == 2 || (j / 16 == 0 && j % 4 == 2)) && k == 1) {
                            continue;
                        }
                        tmp[(j * 4 + k) % 64] = tmp[(j * 4 + k) % 64].add(dp[i][j]);
                    }
                }

                for (int j = 0; j < 64; j++) {
                    if (j != 33 && j != 6 && j != 9) {
                        dp[i + 1][j] = tmp[j];
                    } else {
                        dp[i + 1][j] = new ModInt(0);
                    }
                }
            }


            for (int i = 0; i < 64; i++) {
                res = res.add(dp[n][i]);
            }

