private boolean mysolve(boolean [][] board, int [] M) {
		if (cache.contains(key(board, M)))
			return false;

		if (M[0] == 0)
			return true;
		if (board[M[0]][M[1]])
			return false;

		int lowest = 8;
		for (int i = 7; i >= 0; --i)
			for (int j = 0; j < 8; ++j)
				if (board[i][j])
					lowest = i;

		if (lowest >= M[0])
			return true;


		for (int i = -1; i <= 1; ++i)
			for (int j = -1; j <= 1; ++j) {
				int [] newM = new int [] { M[0] + i, M[1] + j };
				if (newM[0] >= 0 && newM[0] < 8 && newM[1] >= 0 && newM[1] < 8 && !board[newM[0]][newM[1]]) {
					boolean [][] newBoard = newBoard(board);
					if (mysolve(newBoard, newM))
							return true;
				}
			}

		cache.add(key(board, M));
		return false;

	}

