					start_row = row;
				}
			}

			Queue<Position> queue = new LinkedList<>();
			queue.add(new Position(start_row, start_col));
			boolean reached = false;
			while (!queue.isEmpty() && !reached) {
				int row = queue.peek().row;
				int col = queue.poll().col;

				if (col >= n) {
					reached = true;
					break;
				}

