static int solve(int i1, int i2, int t) {

		if(t == 2 * N - 1)
			return 0;
		int j1 = t - i1;
		int j2 = t - i2;

		if(i1 >= N || j1 >= N || i2 >= N || j2 >= N)
			return -INF;


		if(memo[i1][i2][t] != -INF)
			return memo[i1][i2][t];

		return memo[i1][i2][t] = Math.max(solve(i1 + 1, i2 + 1, t + 1), Math.max(solve(i1 + 1, i2, t + 1), Math.max(solve(i1, i2 + 1, t + 1), solve(i1, i2, t + 1))))
				+ cost[i1][j1] + (i1 != i2 ? cost[i2][j2] : 0);
	}

