public void run() {
		FastScanner fs = new FastScanner();
		PrintWriter out = new PrintWriter(System.out);
		System.err.println("Go!");

		int n = fs.nextInt();
		int m = fs.nextInt();
		int x = 0;
		long d = fs.nextInt();
		int[] ps = new int[m];
		int[] bs = new int[m];
		int[] ts = new int[m];
		for(int i = 0; i < m; i++) {
			ps[i] = fs.nextInt() - 1;
			bs[i] = fs.nextInt();
			ts[i] = fs.nextInt();
		}
		long[][] dp = new long[2][n];
		int[] dq = new int[n];
		for(int i = 0; i < m; i++, x ^= 1) {
			long time = i == 0 ? ts[i] - 1 : ts[i] - ts[i-1];
			time *= d;
			int front = 0, tail = 0, right = (int) Math.min(n, time+1);
			int left = -right+1;
			for(int j = 0; j <= Math.min(n-1, time); j++) {
				while(tail > front && dp[x^1][dq[tail-1]] <= dp[x^1][j]) tail--;
				dq[tail++] = j;
			}
			for(int j = 0; j < n; j++) {
				dp[x][j] = bs[i] - Math.abs(ps[i] - j);
				if(front < tail) dp[x][j] += dp[x^1][dq[front]];
				if(right < n) {
					while(tail > front && dp[x^1][dq[tail-1]] <= dp[x^1][right]) tail--;
					dq[tail++] = right++;
				}
				if(front < tail && left >= 0 && dq[front] == left) {
					front++;
				}
				left++;
			}
		}
		long res = Long.MIN_VALUE;
		for(int i = 0; i < n; i++) res = Math.max(res, dp[x^1][i]);
		out.println(res);
		out.close();
	}

