			if(c>0&&b>0)
			{ c--; b--; ans++; }
		}

		if(b==highest) {
			if(c>0&&b>0)
			{ c--; b--; ans++; }
			if(a>0&&b>0)
			{ a--; b--; ans++; }
			if(c>0&&a>0)
			{ c--; a--; ans++; }
		}

		if(c==highest) {
			if(c>0&&b>0)
			{ c--; b--; ans++; }
			if(a>0&&c>0)
			{ a--; c--; ans++; }
			if(a>0&&b>0)
