static void dfs(int v, int d, int prev){
        visited[v]=1;
        for(int i=0; i<visited.length; i++){
            if(i!=prev && graph[v][i] && visited[i]==1){
                int curAnc=v;
                while(curAnc!=i){
                    stack.push(curAnc);
                    visited[curAnc]=2;
                    curAnc=ancestors[curAnc];
                }
                visited[i]=2;
                stack.push(i);
                stack.push(v);
            }
            if (graph[v][i] && visited[i]==0) {
                ancestors[i]=v;
                dfs(i,d+1,v);
            }
        }
        visited[v]=2;
    }

