public static void main(String[] args){ 
		FastReader sc = new FastReader();

		int n = sc.nextInt();
		int m = sc.nextInt();
		int[][] mat = new int[n][m];
		int[][] dist = new int[n][m];

		for(int i=0;i<n;i++)
			Arrays.fill(dist[i], -1);

		Pair start=null, end=null;

		for(int i=0;i<n;i++){
			char[] arr = sc.nextLine().toCharArray();
			for(int j=0;j<m;j++){
				if(arr[j]=='S')
					start = new Pair(i,j,0);
				else if(arr[j]=='E')
					end = new Pair(i,j,0);
				else
					mat[i][j] = arr[j]=='T'?-1:arr[j]-'0';
			}
		}

		PriorityQueue<Pair> queue = new PriorityQueue<Pair>(new Comparator<Pair>(){
			public int compare(Pair a, Pair b){
				return a.d-b.d;
			}
		});

		queue.add(end);
		while(queue.size()>0){
			Pair cur = queue.remove();
			int i=cur.x, j=cur.y;
			if(i<0 || j<0 || i>=n || j>=m || mat[i][j]==-1)
				continue;
			if(dist[i][j] != -1)
				continue;

			dist[i][j] = cur.d;
			queue.add(new Pair(i-1, j, cur.d+1));
			queue.add(new Pair(i, j-1, cur.d+1));
			queue.add(new Pair(i, j+1, cur.d+1));
			queue.add(new Pair(i+1, j, cur.d+1));
		}

		int ans = 0;
		int mindist = dist[start.x][start.y];

		for(int i=0;i<n;i++)
			for(int j=0;j<m;j++)
				if(dist[i][j]<=mindist && dist[i][j]!=-1)
					ans+=mat[i][j];

		System.out.println(ans);
	}

