		if (d2 == 0 || d3 == 0 || d4 == 0)
			return false;
		if (d2 == d3 && 2 * d2 == d4 && 2 * d2 == distSq(p2, p3)) {
			int d = distSq(p4, p2);
			return d == d2 && d == distSq(p4, p3);
		}
		return false;
	}

