            long x = d[2];
            long y = d[3];

            if (y % x != 0) {
                out.println(0);
                return;
            }

            long res = 0;
            long withoutGCD = y / x;
            if (withoutGCD == 1 && x >= l && x <= r) {
                out.println(1);
                return;
            }

            long lb = (long) Math.max(Math.ceil((double) l / x), 1);
            long ub = Math.max(r / x, 1);

            for (long i = lb; i <= ub && i * i < withoutGCD; i++) {
                if (withoutGCD % i == 0 && withoutGCD / i <= ub && gcd(i, withoutGCD / i) == 1) {
                    res += 2;
                }
            }

            out.println(res);
        }

