private static void third() throws Exception {
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		int t = Integer.parseInt(br.readLine());
		StringBuilder sb = new StringBuilder();

		while (t-- > 0) {
			String[] scn = (br.readLine()).trim().split(" ");
			int n = Integer.parseInt(scn[0]);
			int[] time = new int[n + 1];
			int[] pos = new int[n];
			for (int i = 0; i < n; i++) {
				scn = (br.readLine()).trim().split(" ");
				time[i] = Integer.parseInt(scn[0]);
				pos[i] = Integer.parseInt(scn[1]);
			}
			int[] arr = new int[n + 1];
			int prev = 0;
			int cp = pos[0];
			int count = 0;
			long ignore = (long)time[0] + Math.abs(cp);
			arr[0] = 0;
			for (int i = 1; i < n; i++) {
				if (ignore <= time[i]) {
					arr[i] = cp;
					prev = cp;
					cp = pos[i];
					ignore = (long)time[i] + Math.abs(cp - prev);

				} else {
					if (prev < cp) {
						arr[i] = prev + time[i] - time[i - 1];

					} else {
						arr[i] = prev - (time[i] - time[i - 1]);
					}
					prev = arr[i];
				}
			}
			arr[n] = cp;
			for (int i = 0; i < n; i++) {
				if ((arr[i] <= pos[i] && pos[i] <= arr[i + 1] )||( arr[i + 1] <= pos[i] && pos[i] <= arr[i])) {
					count += 1;
				}
			}
			sb.append(count);
			sb.append("\n");
		}
		System.out.println(sb);
		return;
	}

