            if (Integer.bitCount(bit) >= K) {
                int currentMax = 0;
                long add = 0;
                for (int i = 0; i < N; i++) {




                    if ((bit & (1 << i)) != 0) {
                        add += Math.max(0, currentMax - buildings[i] + 1);
                        currentMax = Math.max(currentMax + 1, buildings[i]);
