            v.add(new int[]{wa[i], wb[i]});
        }

        int[][] ans = new int[data.size() + 1][w + 1];
        int cur = 0;
        for (List<int[]> mm : data.values()) {

            cur++;
            ans[cur] = Arrays.copyOf(ans[cur - 1], w + 1);
            for (int[] pos : mm) {
                for (int i = 0; i <= w; i++) {
                    if (i + pos[0] > w) break;
                    ans[cur][i + pos[0]] = Math.max(ans[cur][i + pos[0]], ans[cur - 1][i] + pos[1]);
                }
            }
            for (int l = 1; l <= w; l++) {
