		HashSet<Integer> visited = new HashSet<Integer>(); visited.add(start);
		while(!s.isEmpty()){
			int p = s.pop();
			for(int neighbor: tree.get(p-1)){
				if(neighbor != prev){
					if(colors[neighbor-1] != color) return -1;
					if(!visited.contains(neighbor)) {s.push(neighbor); visited.add(neighbor);} 
				}
			}
		}
		return color;
	}

