		for (int i = 0; i < m; i++) {
			if(empLang[emp][i]){
				searchedSet.add(emp);
				for (int j = 0; j < empLang.length; j++) {
					if(empLang[j][i]){
						foundSet.add(j);
					}
				}
			}
		}
		foundSet.removeAll(searchedSet);
		while(!foundSet.isEmpty()){
