            for (int i = start; i <= end; ++i) {
                for (int j = i + 1; j <= end; ++j) {
                    for (int k = j + 1; k <= end; ++k) {
                        if (a[i] <= a[j] && a[j] <= a[k])
                            return false;
                        if (a[i] >= a[j] && a[j] >= a[k])
                            return false;
                    }
                }
            }
            return true;
        }

