private static boolean reach(int[][] g, int[] arr, int buy) {
		int n = g.length;
		int[] ok = new int[n];
		Arrays.fill(ok, -1);
		ok[0]=buy;
		Queue<Integer> q = new LinkedList<Integer>();
		boolean[] inQueue = new boolean[n];
		inQueue[0]=true;
		q.add(0);
		while(!q.isEmpty()){
			int u = q.poll();
			inQueue[u]=false;
			for(int v=0;v<n;v++)
				if(u!=v && g[u][v]<=ok[u]){
					int next = ok[u]-g[u][v]+arr[v];
					if(next>ok[v]){
						ok[v]=next;
						if(!inQueue[v]){
							inQueue[v]=true;
							q.add(v);
						}
					}
				}
		}
		return ok[n-1]!=-1;
	}

