private long dp(int n, int h, long[][] dpt) {
		if (n == 0) {
			return (h == 0) ? 1 : 0;
		}
		if (n == 1) {
			return (h == 1) ? 1 : 0;
		}
		if (h == 1) {
			return (n == 1) ? 1 : 0;
		}
		if (n < h) {
			return 0;
		}
		if (dpt[n][h] < 0) {

			long counter = 0;
			for (int i = 0; i < n; ++i) {
				int left = i;
				int right = n - 1 - i;
				for (int h1 = 0; h1 < h; ++h1) {
					for (int h2 = 0; h2 < h; ++h2) {
						if (Math.max(h1, h2) == h - 1) {
							long tmp = dp(left, h1, dpt) * dp(right, h2, dpt);
							counter += tmp;
						}
					}
				}
			}
			dpt[n][h] = counter;
		}
		return dpt[n][h];
	}

