static int go(int i, int[][] arr, int[] dp) {
        if (i >= arr[0].length) return 0;
        if (dp[i] != -1) return dp[i];

        int max = 0;
        if (arr[0][i] != 0 && arr[1][i] != 0) {
            max = go(i + 1, arr, dp);
        } else if(arr[0][i] != 1 && arr[1][i] != 1) {
            max = go(i + 1, arr, dp) + 1;
        } else {
            max = go(i + 1, arr, dp) + 2;
        }

        if (i + 1 < arr[0].length) {
            int zeros = 0;
            int ones = 0;
            for (int r = 0; r < 2; r++) {
                for (int col = i; col <= i + 1; col++) {
                    if (arr[r][col] == 1) {
                        ones++;
                    } else {
                        zeros++;
                    }
                }
                if (zeros > 0 && ones > 0) {
                    max = Math.max(go(i + 2, arr, dp) + 2, max);
                } else if (zeros > 0) {
                    max = Math.max(go(i + 2, arr, dp) + 1, max);
                } else {
                    max = Math.max(go(i + 2, arr, dp), max);
                }
            }
        }
        dp[i] = max;
        return dp[i];
    }

