			long decimal = 10;
			int lastGoodIndex = i;
			for (int j = i - 1; j >= 0; j--) {
				int digit = k[j] - '0';
				if (sum + decimal * digit < n && decimal <= n) {
					sum += decimal * digit;
					decimal *= 10;
					if (digit != 0) {
						lastGoodIndex = j;
					}
				} else {
					break;
				}
			}
			i = lastGoodIndex;
			answer += sum * power;
			power *= n;
		}

		out.println(answer);

	}

