boolean firstWin(int n) {
        boolean[] fWin = new boolean[1 << n];
        for (int st = 1; st < 1 << n; st++) {
            for (int ch = 0; ch < n; ch++)
                if (((1 << ch) & st) != 0) {
                    int newSt = st;
                    int k = ch + 1;
                    while (k <= n) {
                        if (((1 << (k - 1)) & newSt) != 0)
                            newSt ^= 1 << (k - 1);
                        k *= ch + 1;
                        if (k == 1)
                            break;
                    }
                    if (!fWin[newSt]) {
                        fWin[st] = true;
                    }
                }
        }
        return fWin[(1 << n) - 1];
    }

