int furthestVertex2(int start, boolean[] cant, boolean[] visited, int[] queue, int[] fromStart) {
            int queueSize = 0;
            Arrays.fill(fromStart, INF);
            fromStart[start] = 0;
            visited[start] = true;
            queue[queueSize++] = start;
            int maxDist = 0, res = -1;
            for (int frontPtr = 0; frontPtr < queueSize; frontPtr++) {
                int cur = queue[frontPtr];
                for (int nxt : adj[cur]) {
                    if (fromStart[nxt] == INF && !cant[nxt]) {
                        queue[queueSize++] = nxt;
                        visited[nxt] = true;
                        fromStart[nxt] = fromStart[cur] + 1;
                        if (fromStart[nxt] > maxDist) {
                            maxDist = fromStart[nxt];
                            res = nxt;
                        }
                    }
                }
            }
            return res;
        }

