private int count(String cells, String pattern) {
		int result = 0;
		char[] array = cells.toCharArray();
		while (true) {
			boolean ok = true;
			for (int i = 0; i < cells.length() - 1; ++i) {
				if (array[i] == array[i + 1]) {
					ok = false;
					if (array[i] != pattern.charAt(i & 1)) {
						array[i] ^= 1;
					}
					if (array[i + 1] != pattern.charAt((i + 1) & 1)) {
						array[i + 1] ^= 1;
					}
					++result;
				}
			}
			if (ok) {
				break;
			}
		}
		return result;
	}

