private void bfs(Set<Integer> stations, ArrayList<ArrayList<Integer>> g, int d,
                         int[] components) {

            LinkedList<Integer> toVisit = new LinkedList<>();
            toVisit.addAll(stations);
            LinkedList<Integer> nextLevel = new LinkedList<>();

            int distance = 0;
            while (!toVisit.isEmpty() && distance <= d) {
                for (int node : toVisit) {
                    for (int nbr : g.get(node)) {
                        if (!stations.contains(components[nbr])) {
                            components[nbr] = components[node];
                            nextLevel.add(nbr);
                        }
                    }
                }

                LinkedList<Integer> tmp = toVisit;
                toVisit = nextLevel;
                nextLevel = tmp;

                nextLevel.clear();
                distance++;
            }

        }

