public static int costCheck(int select, int cost, int ceiling) {
		int direct = c[select][1] + cost;
		for (int i = 0; i <= 9; i++) {
			if (i != 1 && i != select) {
				if (direct > c[select][i] + cost && cost + c[select][i] < ceiling) {
					int ret = costCheck(i, cost + c[select][i], ceiling);
					if (ret < direct) {
						direct = ret;
					}
				}
			}
		}
		if (direct < ceiling) {
			return direct;
		} else {
			return ceiling;
		}
	}

