public boolean nextPermutation(String[] permutateString) {
        int L = permutateString.length;
        boolean ok = false;
        for (int i = L - 1; i >= 1; i--) {
            if(permutateString[i].compareTo(permutateString[i - 1]) > 0) {
                reverse(permutateString, i, L);
                for (int j = i; j < L; j++) {
                    if(permutateString[i - 1].compareTo(permutateString[j]) < 0) {
                        swap(permutateString, i - 1, j);
                        return true;
                    }
                }
            }
        }
        return ok;
    }

