			Deque<Node> stack = new ArrayDeque<Node>();
			String num = "";

			line = br.readLine();
			for (char c : line.toCharArray()) {
				switch (c) {
					case '[':
						Node node = new Node();
						if (!stack.isEmpty()) {
							node.parent = stack.peek();
							stack.peek().children.add(node);
						}
						stack.push(node);
						break;
					case ']':
						if (num.length() > 0) {
							stack.peek().nums.add(parseInt(num));
							num = "";
						}
						if (stack.size() != 1) {
							stack.pop();
						} else {
							tree.root = stack.pop();
						}
						break;
					default:
						num += c;
						break;
				}
			}
			System.out.println(tree.solve());
		}
	}

