private static int leftBS(ArrayList<Integer> arrayList, int i) {
        int left = 0, right = arrayList.size() -1, middle;
        while (left!=right) {
            if (left+1==right) {
                if (arrayList.get(left)<= i) {
                    if (arrayList.get(right)<=i) return right;
                    else return left;
                }
                else return left;
            }
            middle = (left+right)/2;
            if (arrayList.get(middle)<i) {
                left = middle;
            }
            else if (arrayList.get(middle)>i) {
                right = middle;
            }
            else return middle;
        }
        return left;
    }

