static int solve2() {
		int len = 0;

		for(int i = 0;i < n;i++) {
			for(int j = i;j < n;j++) {
				if((j - i + 1) % 2 == 0) {
					if(isEqual(i, j)) {
						if(j - i + 1 > len) {
