public static void main(String[] args)
	{
		Scanner in = new Scanner(System.in);

		int n = in.nextInt();
		int m = in.nextInt();
		int k = in.nextInt();

		boolean[][] table = new boolean[Math.max(n, m)][Math.min(n, m)];
		for(int x = 0; x < n; x++)
		{
			for(int y = 0; y < m; y++)
			{
				if(n >= m)
				{
					table[x][y] = in.nextInt() == 1;
				}
				else
				{
					table[y][x] = in.nextInt() == 1;
				}
			}
		}

		n = table.length;
		m = table[0].length;

		int result = n * m;

		if(n <= k)
		{
			for(int z = 0; z < (1 << m); z++)
			{
				int current = 0;

				for(int a = 0; a < m; a++)
				{
					if((z & (1 << a)) > 0)
					{
						table[0][a] = !table[0][a];
						current++;
					}
				}

				for(int b = 1; b < table.length; b++)
				{
					int row = 0;
					for(int c = 0; c < table[0].length; c++)
					{
						if(table[b][c] != table[0][c])
						{
							row++;
						}
					}

					current += Math.min(row, table[0].length - row);
				}

				result = Math.min(result, current);

				for(int d = 0; d < m; d++)
				{
					if((z & (1 << d)) > 0)
					{
						table[0][d] = !table[0][d];
					}
				}
			}
		}
		else
		{
			for(int e = 0; e < table.length; e++)
			{
				int current = 0;

				for(int f = 0; f < table.length; f++)
				{
					int row = 0;
					for(int g = 0; g < table[0].length; g++)
					{
						if(table[f][g] != table[e][g])
						{
							row++;
						}
					}

					current += Math.min(row, table[0].length - row);
				}

				result = Math.min(result, current);
			}
		}

		if(result > k)
		{
			System.out.println(-1);
		}
		else
		{
			System.out.println(result);
		}
	}

