			int n = Integer.parseInt(st.nextToken());
			long k = Integer.parseInt(st.nextToken());
			long x = Long.parseLong(st.nextToken()) - 1;
			String s = fin.readLine();
			boolean hasA = false;
			ArrayList<Long> sequence = new ArrayList<Long>();
			char prev = 'a';
			for(int i = 0; i < s.length(); i++) {
				char c = s.charAt(i);
				if(c == '*') {
					if(prev == 'a') {
						sequence.add(k);
					}
					else {
						sequence.set(sequence.size() - 1, sequence.get(sequence.size() - 1) + k);
					}
				}
				prev = c;
				if(c == 'a') {
					hasA = true;
				}
			}
			if(!hasA) {
				x ++;
			}

			ArrayList<Long> ans = new ArrayList<Long>();
			for(int i = 0; i < sequence.size(); i++) {
				ans.add((long) 0);
			}
			long mult = 1;
			int index = 0;
			outer:
			for(int i = sequence.size() - 1; i >= 0; i--) {

				long count = 1;
				while(count <= sequence.get(i) + 1) {
					if(mult * count > x) {
						index = i;
						break outer;
					}
					count ++;
				}
				mult *= sequence.get(i) + 1;
			}

			for(int i = index; i < sequence.size(); i++) {

				ans.set(i, x / mult);
				x %= mult;
				if(i != sequence.size() - 1) {
					mult /= sequence.get(i + 1) + 1;
				}
			}

			int counter = 0;
			outer:
			for(int i = 0; i < s.length(); i++) {
				char c = s.charAt(i);
				if(c == '*') {
					while(s.charAt(i) == '*') {
						i ++;
						if(i == s.length()) {
							break;
						}
					}
					i--;
					for(long j = 0; j < ans.get(counter); j++) {
						fout.append("b");
					}
					counter ++;
				}
				else {
					fout.append("a");
				}
			}
			fout.append("\n");
		}
		System.out.print(fout);
	}

public static void dijkstra(point source, boolean[][] vis, char[][] labyrinth, point[][] points)
	{
		Queue<point> queue = new PriorityQueue<>(2000001, new NodeComp());
		queue.add(source);
		vis[source.x][source.y]=true;
		while (!queue.isEmpty())
		{
			point p = queue.poll();
			int x=p.x;
			int y=p.y;
			if (x-1>=0 && labyrinth[x-1][y]!='*' && relax(x-1, y, p.remL, p.remR, points))
			{
				if (points[x-1][y].remL==-1)
				{
					points[x-1][y].remL = p.remL;
					points[x-1][y].remR = p.remR;
					queue.add(points[x-1][y]);
				}
				else
				{
					points[x-1][y].remL = p.remL;
					points[x-1][y].remR = p.remR;

					queue.add(points[x-1][y]);
				}
				vis[x-1][y] = true;
			}
			if (y-1>=0 && labyrinth[x][y-1]!='*' && relax(x, y-1, p.remL-1, p.remR, points) && p.remL>0)
			{
				if (points[x][y-1].remL==-1)
				{
					points[x][y-1].remL = p.remL-1;
					points[x][y-1].remR = p.remR;
					queue.add(points[x][y-1]);
				}
				else
				{
					points[x][y-1].remL = p.remL-1;
					points[x][y-1].remR = p.remR;

					queue.add(points[x][y-1]);
				}
				vis[x][y-1] = true;
			}
			if (x+1<labyrinth.length && relax(x+1,y,p.remL, p.remR, points) && labyrinth[x+1][y]!='*')
			{
				if (points[x+1][y].remL==-1)
				{
					points[x+1][y].remL = p.remL;
					points[x+1][y].remR = p.remR;
					queue.add(points[x+1][y]);
				}
				else
				{
					points[x+1][y].remL = p.remL;
					points[x+1][y].remR = p.remR;

					queue.add(points[x+1][y]);
				}
				vis[x+1][y] = true;
			}
			if (y+1<labyrinth[0].length && relax(x,y+1, p.remL, p.remR-1, points) && labyrinth[x][y+1]!='*' && p.remR>0)
			{
				if (points[x][y+1].remL==-1)
				{
					points[x][y+1].remL = p.remL;
					points[x][y+1].remR = p.remR-1;
					queue.add(points[x][y+1]);
				}
				else
				{
					points[x][y+1].remL = p.remL;
					points[x][y+1].remR = p.remR-1;

					queue.add(points[x][y+1]);
				}
				vis[x][y+1] = true;
			}

		}
	}

