public void run() throws IOException
{   
in = new Scanner(System.in);
out = new PrintWriter(System.out);

int vx = in.nextInt();
int vy = in.nextInt();
int px = in.nextInt();
int py = in.nextInt();
int wx1 = in.nextInt();
int wy1 = in.nextInt();
int wx2 = in.nextInt();
int wy2 = in.nextInt();
int mx1 = in.nextInt();
int my1 = in.nextInt();
int mx2 = in.nextInt();
int my2 = in.nextInt();

Line2D vp = new Line2D.Double(vx,vy,px,py);
Line2D wall = new Line2D.Double(wx1,wy1,wx2,wy2);
Line2D mirror = new Line2D.Double(mx1,my1,mx2,my2);

if(!wall.intersectsLine(vp))
    {

    int vpx = px-vx;
    int vpy = py-vy;
    int mirrorX = mx2-mx1;
    int mirrorY = my2-my1;




    if(vpx*mirrorY-vpy*mirrorX==0)
        {
        out.println("YES");
        out.close();
        return;
        }

    if(!mirror.intersectsLine(vp))
        {
        out.println("YES");
        out.close();
        return;
        }       
    }


int mirrorX = mx2-mx1;
int mirrorY = my2-my1;

int normalX = -mirrorY;
int normalY = mirrorX;

int ma = normalX;
int mb = normalY;
int mc = -ma*mx1-mb*my1;

int signv = ma*vx+mb*vy+mc;
int signp = ma*px+mb*py+mc;

signv = signv==0 ? 0 : signv/Math.abs(signv);
signp = signp==0 ? 0 : signp/Math.abs(signp);

if(signv*signp<=0)
    {
    out.println("NO");
    out.close();
    return;
    }

double pdist = mirror.ptLineDist(px,py);
double normalLength = Math.sqrt(normalX*normalX+normalY*normalY);
double normX = normalX*pdist/normalLength;
double normY = normalY*pdist/normalLength;

double p1X = px+2*normX;
double p2X = px-2*normX;
double p1Y = py+2*normY;
double p2Y = py-2*normY;

double p1dist = mirror.ptLineDist(p1X,p1Y);
double p2dist = mirror.ptLineDist(p2X,p2Y);
double qX,qY;
if(p1dist<p2dist) 
    {
    qX = p1X;
    qY = p1Y;
    }
else 
    {
    qX = p2X;
    qY = p2Y;
    }

Line2D imaginaryLine = new Line2D.Double(vx,vy,qX,qY);
if(!mirror.intersectsLine(imaginaryLine))
    {
    out.println("NO");
    out.close();
    return;
    }

double lx = vx;
double ly = vy;
double rx = qX;
double ry = qY;
double medx,medy;

while(Math.sqrt((lx-rx)*(lx-rx)+(ly-ry)*(ly-ry))>1e-4)
    {
    medx = (lx+rx)/2;
    medy = (ly+ry)/2;
    if(mirror.relativeCCW(medx,medy)==mirror.relativeCCW(vx,vy))
        {
        lx = medx;
        ly = medy;
        }
    else 
        {
        rx = medx;
        ry = medy;
        }
    }

medx = (lx+rx)/2;
medy = (ly+ry)/2;

Line2D vmirror = new Line2D.Double(vx,vy,medx,medy);
Line2D pmirror = new Line2D.Double(px,py,medx,medy);
if(wall.intersectsLine(vmirror)||wall.intersectsLine(pmirror)) out.println("NO");
else out.println("YES");
out.close();

}

public CF1133F2() {
		FS scan = new FS();
		PrintWriter out = new PrintWriter(System.out);
		int n = scan.nextInt(), m = scan.nextInt(), D = scan.nextInt();
		int deg = 0;
		Graph g = new Graph(n);
		for(int i = 0 ; i < m ; i++) {
			int u = scan.nextInt() - 1, v = scan.nextInt() - 1;
			g.add(u, v);
			if(u == 0 || v == 0) deg++;
		}
		if(deg < D) {
			out.println("NO");
		} else {
			Deque<Integer> q = new ArrayDeque<>();
			boolean[] visited = new boolean[n];
			visited[0] = true;
			DSU dsu = new DSU(n);
			for(int c : g.adj[0]) {
				if(!visited[c]) {
					visited[c] = true;
					q.add(c);
					while(!q.isEmpty()) {
						int u = q.pop();
						for(int v : g.adj[u]) {
							if(!visited[v]) {
								visited[v] = true;
								dsu.union(u, v);
								q.add(v);
							}
						}
					}
				}
			}
			Set<Integer> cmp = new HashSet<>();
			for(int c : g.adj[0])
				cmp.add(dsu.find(c));
			if(cmp.size() > D) {
				out.println("NO");
			} else {
				out.println("YES");
				boolean[] used = new boolean[n];
				Arrays.fill(visited, false);
				visited[0] = true;
				for(int c : g.adj[0]) {
					if(!used[dsu.find(c)]) {
						out.printf("1 %d%n", c + 1);
						used[dsu.find(c)] = true;
						visited[c] = true;
						q.add(c);
					}
				}
				int left = D - cmp.size();
				for(int c : g.adj[0]) {
					if(left > 0 && !visited[c]) {
						out.printf("1 %d%n", c + 1);
						visited[c] = true;
						q.add(c);
						left--;
					}
				}
				while(!q.isEmpty()) {
					int u = q.pop();
					for(int v : g.adj[u]) {
						if(!visited[v]) {
							out.printf("%d %d%n", u + 1, v + 1);
							visited[v] = true;
							q.add(v);
						}
					}
				}
			}
