					int temp_r = s_r[i+k-1] - s_r[i] + R[i];
					if (temp_r > max) max = temp_r ;
					int temp_g = s_g[i+k - 1] - s_g[i] + G[i] ;
					if (temp_g > max) max = temp_g;
					int temp_b = s_b[i+k - 1] - s_b[i] + B[i];
					if (temp_b > max) max = temp_b;
				}
				System.out.println(k-max);
			}
		}
	}

