                at.add(in.nextInt());
            } else {
                df.add(in.nextInt());
            }
        }

        Collections.sort(at);
        Collections.sort(df);

        int[] attack = new int[m];
        int total = 0;
        for (int i = 0; i < m ; i++) {
            attack[i] = in.nextInt();
            total += attack[i];
        }
        Arrays.sort(attack);

        int best = 0;
        {
            int case1 = 0;
            int ji = 0;
            for (int i = m-1 ; i >= 0 && ji < at.size() ; i--) {
                if (at.get(ji) < attack[i]) {
                    case1 += attack[i] - at.get(ji);
                    ji++;
                } else {
                    break;
                }
            }
            best = Math.max(best, case1);
        }

        {
            int case2 = total;
            boolean[] done = new boolean[m];
            int ok = 0;
            for (int di : df) {
                for (int i = 0 ; i < m ; i++) {
                    if (done[i]) {
