		{
			for(int j = 1; j < C-1; j++)
			{
				if(board[i][j])
				{
					if(board[i-1][j])
						q[i][j] = q[i-1][j] + 1;
					if(board[i][j-1])
						w[i][j] = w[i][j-1] + 1;
				}
			}
