        for (int i = 0; i < s1.length(); ++i) {
            if (s1.charAt(i) == 'R') b1[i] = 0;
            else if (s1.charAt(i) == 'G') b1[i] = 1;
            else b1[i] = 2;
        }
        int[] b2 = new int[s2.length()];
        for (int i = 0; i < s2.length(); ++i) {
            if (s2.charAt(i) == 'R') b2[i] = 0;
            else if (s2.charAt(i) == 'G') b2[i] = 1;
            else b2[i] = 2;
        }

        int ct2[][][] = new int[s2.length()][3][3];

        for (int i = s2.length() - 2; i >= 0; --i) {
            ct2[i + 1][b2[i]][b2[i + 1]] = 1;
        }
        for (int i = 1; i < b2.length; ++i) {
            for (int j = 0; j <= 2; ++j) {
                for (int k = 0; k <= 2; ++k) {
                    ct2[i][j][k] += ct2[i - 1][j][k];
                }
            }
        }

        int[] mark1 = new int[b1.length];
        Arrays.fill(mark1,  -1);

        long res = 0;
        int[] earliest1 = new int[b1.length];
        Arrays.fill(earliest1, -1);
        earliest1[0] = 0;
        int ind = 0;
        for (int i = 0; i < b1.length; ++i) {
            if (i > 0 && b1[i - 1] == b2[ind]) {
                ind++;
            }
            if (ind >= b2.length) {
                break;
            }
            earliest1[i] = ind;
        }

        ind = 0;
        for (int i = 0; i < b2.length; ++i) {
            if (i > 0 && b2[i - 1] == b1[ind]) {
                ind++;
            }
            if (ind >= b1.length) {
                break;
            }
            mark1[ind] = i;
        }

        for (int i = 0; i < b1.length; ++i) {
            int start = earliest1[i];
            if (start < 0) continue;
            int end = b2.length - 1;
            if (mark1[i] != -1) {
                end = mark1[i];
            }
            res += end - start + 1;
            if (i > 0 && b1[i - 1] != b1[i]) {
                int c1 = b1[i - 1];
                int c2 = b1[i];
                res -= ct2[end][c2][c1];
                if (start > 0) {
                    res += ct2[start - 1][c2][c1];
                }
            }
        }

        out.printLine(res);
    }

