public void solve() {
        String first = io.readLine();
        int[] play = io.readIntArray();

        int win = play[play.length - 1];
        int lose = win == 2 ? 1 : 2;
        int winCount = 0, loseCount = 0;
        int[] accWin = new int[play.length * 2];
        int[] accLose = new int[play.length * 2];
        for (int i = 0; i <= play.length; i++) {
            accWin[i] = winCount;
            accLose[i] = loseCount;
            if (i < play.length) {
                if (play[i] == win) winCount++;
                else loseCount++;
            }
        }
        for (int i = play.length; i < accWin.length; i++) {
            accWin[i] = accWin[play.length];
            accLose[i] = accLose[play.length];
        }

        List<Pair> res = new ArrayList<Pair>();

        for (int t = 2; t < winCount; t++) {
            int cur = 0;
            int winscore = 0;
            int losescore = 0;
            int lastV = 0;
            boolean bad = false;
            for (; cur < play.length; ) {
                int left = cur;
                int right = cur + t + t - 1;
                int bw = accWin[left];
                int bl = accLose[left];
                while (left <= play.length && left < right) {
                    int m = (left + right) / 2;
                    if (accWin[m] - bw >= t || accLose[m] - bl >= t) {
                        right = m;
                    } else left = m + 1;
                }
                if (accWin[left] - bw == t) {
                    winscore++;
                    lastV = win;
                } else if (accLose[left] - bl == t) {
                    losescore++;
                    lastV = lose;
                } else {
                    bad = true;
                    break;
                }
                cur = left;
            }
            if (!bad && winscore > losescore && lastV == win) {
                Pair p = new Pair();
                p.s = winscore;
                p.t = t;
                res.add(p);
            }
        }

        if (winCount > loseCount) {
            Pair p1 = new Pair();
            p1.s = winCount;
            p1.t = 1;
            Pair p2 = new Pair();
            p2.s = 1;
            p2.t = winCount;
            res.add(p1);
            if (winCount != 1)
                res.add(p2);
        }

        res.sort(new Comparator<Pair>() {
            @Override
            public int compare(Pair p1, Pair p2) {
                if (p1.s == p2.s) return p1.t - p2.t;
                return p1.s - p2.s;
            }
        });

        io.writeLine(Integer.toString(res.size()));
        for (int i = 0; i < res.size(); i++) {
            io.writeLine(res.get(i).s + " " + res.get(i).t);
        }

    }

