public static void main(String[] args)throws IOException
    {
        Reader in = new Reader();
        int t = in.nextInt();
        StringBuilder stringBuilder = new StringBuilder();
        while (t-- > 0)
        {
            long n = in.nextLong();
            int m = in.nextInt();
            long[] A = new long[m];
            for (int i=0;i<m;i++)   A[i] = in.nextLong();
            int[] powers = new int[63];
            for (int i=0;i<m;i++)
            {
                double p = Math.log((double)A[i]) / Math.log(2);
                powers[(int)p]++;
            }
            long ans = 0L;
            boolean flag = true;
            for (int i=0;i<=63;i++)
            {
                long mask = 1L << i;
                if((n & mask) > 0)
                {
                    long tot = 0L;
                    for (int j=0;j<=i;j++)
                    {
                        tot += powers[j] * (1L << j);
                    }
                    if (tot >= mask)
                    {
                        long val = mask;
                        int start = i;
                        while (val > 0 && start >= 0)
                        {
                            long mm = 1L << start;
                            if (mm * powers[start] < val)
                            {
                                val -= mm * powers[start];
                                powers[start] = 0;
                            }
                            else
                            {
                                long req = val / mm;
                                val = 0L;
                                powers[start] -= (int)req;
                            }
                            start--;
                        }
                    }
                    else
                    {
                        boolean ff = false;
                        int reqPower = -1;
                        for (int j=i + 1;j<powers.length;j++)
                        {
                            if (powers[j] > 0)
                            {
                                ff = true;
                                reqPower = j;
                                break;
                            }
                        }
                        if (!ff)
                        {
                            flag = false;
                            break;
                        }
                        else
                        {
                            ans += reqPower - i;
                            powers[reqPower] --;
                            for (int j=reqPower - 1;j>=i;j--)
                            {
                                powers[j]++;
                            }
                        }
                    }
                }
            }
            if (flag)
                stringBuilder.append(ans).append("\n");
            else
                stringBuilder.append("-1\n");
        }
        System.out.println(stringBuilder);
    }

