			if (flag == 0) whiteCount |= 1;
		}
		for (int x = 0;x < w;++ x) {
			int flag = 0;
			for (int y = 0;y < h;++ y) {
				if (grid[y][x]) {
					if (flag == 0) ++ flag;
					if (flag >= 2) {
						out.println(-1);
						return;
					}
				} else {
					if (flag == 1) ++ flag;
				}
			}
			if (flag == 0) whiteCount |= 2;
		}
		if (whiteCount % 3 != 0) {
			out.println(-1);
			return;
		}
		Queue<Point> bfs = new ArrayDeque<Point>();
		int ans = 0;
		for (int y = 0;y < h;++ y) {
			for (int x = 0;x < w;++ x) {
				if (grid[y][x]) {
					bfs.add(new Point(x, y));
					++ ans;
					while(!bfs.isEmpty()) {
						Point tmp = bfs.poll();
						if (tmp.y - 1 >= 0 && grid[tmp.y - 1][tmp.x]) {
							bfs.add(new Point(tmp.x, tmp.y - 1));
							grid[tmp.y - 1][tmp.x] = false;
						}
						if (tmp.y + 1 < h && grid[tmp.y + 1][tmp.x]) {
							bfs.add(new Point(tmp.x, tmp.y + 1));
							grid[tmp.y + 1][tmp.x] = false;
						}
						if (tmp.x - 1 >= 0 && grid[tmp.y][tmp.x - 1]) {
							bfs.add(new Point(tmp.x - 1, tmp.y));
							grid[tmp.y][tmp.x - 1] = false;
						}
						if (tmp.x + 1 < w && grid[tmp.y][tmp.x + 1]) {
							bfs.add(new Point(tmp.x + 1, tmp.y));
							grid[tmp.y][tmp.x + 1] = false;
						}
					}
				}
			}
		}
		out.println(ans);
	}

