				pq.add(new Pair(v.get(ptr).y2, v.get(ptr).x1));
				ptr++;
			}
			while(pq.size() > 0 && pq.peek().val < h.get(i).y1)
			{
				Pair p = pq.poll();
				tree.update(p.idx, -1);
			}
			ret -= tree.query(h.get(i).x1, h.get(i).x2);
		}
