                        mint[i][j] = two[i][j];
                        continue;
                    }
                    minf[i][j] = Math.min(((i > 0) ? minf[i - 1][j] : (int) 1e6), ((j > 0) ? minf[i][j - 1] : (int) 1e6)) + fv[i][j];
                    mint[i][j] = Math.min(((i > 0) ? mint[i - 1][j] : (int) 1e6), ((j > 0) ? mint[i][j - 1] : (int) 1e6)) + two[i][j];
                }
            }
