			Collections.sort(b);
			long cur = 0;
			int takeB = needBeHigher - c;
			if (takeB > b.size()) {
				continue;
			}
			if (takeB < 0) {
				takeB = 0;
			}
			int score = 0;
			int ai = 0;
			int bi = 0;
			while (takeB > 0) {
				takeB--;
				cur += b.get(bi);
				bi++;
				score++;
			}
			while (score < gotPoints) {
				if (bi < b.size() && (ai == a.size() || b.get(bi) < a.get(ai))) {
					cur += b.get(bi);
					bi++;
					score++;
				} else if (ai < a.size()) {
					cur += a.get(ai);
					ai++;
					score++;
				} else {
					break;
				}
			}
			if (score >= gotPoints) {
				ans = Math.min(ans, cur);
			}
		}






		System.out.println(ans == inf ? -1 : ans);
	}

