public static void main(String[] args) throws IOException {
        Scanner in = new Scanner(System.in);
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] s = br.readLine().split(" ");
        int n = Integer.parseInt(s[0]);
        int m = Integer.parseInt(s[1]);
        Node[] nodes = new Node[n*m];
        int[][] mp = new int[n][m];
        for (int i = 0; i < n; i++) {
            s = br.readLine().split(" ");
            for (int j = 0; j < m; j++) {
                int x = Integer.parseInt(s[j]);
                nodes[i*m+j] = new Node(x, i, j);
                mp[i][j] = x;
            }
        }
        Arrays.sort(nodes);
        int[][][] connections = new int[4][n][m];

        for (int k = 0; k < 4; k++)
            for (int i = 0; i < n; i++)
                for (int j = 0; j < m; j++)
                    connections[k][i][j] = -1;
        for (int i = 0; i < n; i++) {
            Map<Integer, Integer> cache = new HashMap<>();
            for (int j = 0; j < m; j++) {
                if (cache.containsKey(mp[i][j])) {
                    int y = cache.get(mp[i][j]);
                    connections[0][i][y] = j;
                    connections[1][i][j] = y;
                }
                cache.put(mp[i][j], j);
            }
        }
        for (int j = 0; j < m; j++) {
            Map<Integer, Integer> cache =new HashMap<>();
            for (int i = 0; i < n; i++) {
                if (cache.containsKey(mp[i][j])) {
                    int x= cache.get(mp[i][j]);
                    connections[2][x][j] = i;
                    connections[3][i][j] = x;
                }
                cache.put(mp[i][j], i);
            }
        }

        boolean[][] visit = new boolean[n][m];
        int[] maxR = new int[n];
        int[] maxC = new int[m];
        Queue<Integer> queue = new LinkedList<>();


        int[] nums = new int[n*m*2];
        int nm = n*m;
        int nn =0;
        for (int i =0; i < nm; i++) {
                int val = 0;
                if (!visit[nodes[i].x][nodes[i].y]) {
                    nums[nn++] = nodes[i].x;
                    nums[nn++] = nodes[i].y;
                    queue.add(nodes[i].x);
                    queue.add(nodes[i].y);
                    visit[nodes[i].x][nodes[i].y] = true;
                    while (!queue.isEmpty()) {
                        int x = queue.poll();
                        int y = queue.poll();
                        val = Math.max(maxR[x]+1, val);
                        val = Math.max(maxC[y]+1, val);
                        for (int k = 0; k < 4; k++) {
                            if (connections[k][x][y] >= 0) {
                                int xx = k >= 2 ? connections[k][x][y] : x;
                                int yy = k >= 2 ? y : connections[k][x][y];
                                if (!visit[xx][yy]) {
                                    queue.add(xx);
                                    queue.add(yy);
                                    nums[nn++]=xx;
                                    nums[nn++]=yy;
                                    visit[xx][yy]=true;
                                }
                            }
                        }
                    }
                    for (int k = 0; k < nn; k+=2) {
                        int x = nums[k];
                        int y = nums[k+1];
                        maxR[x] = val;
                        maxC[y] = val;
                        mp[x][y] = val;
                    }
                    nn = 0;
                }
        }

        PrintWriter pw = new PrintWriter(new OutputStreamWriter(System.out));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (j != 0) pw.print(' ');
                pw.print(mp[i][j]);
            }
            pw.println();
        }
        pw.close();
    }

public void solve(int testNumber, InputReader in, PrintWriter out) {
            int N = in.nextInt();
            int[] arr = new int[N];
            HashSet<Integer> seen = new HashSet<>();
            for (int i = 0; i < N; i++) {
                int a = in.nextInt();
                arr[i] = a;
                seen.add(a);
            }
            for (int i = 0; i < 7; i++) {
                seen.add(i);
            }
            ArrayList<Integer> mapping = new ArrayList<Integer>(seen);
            DoubleMap map = new DoubleMap();
            for (int i = 0; i < mapping.size(); i++) {
                map.add(mapping.get(i), i);
            }
            int sz = mapping.size();
            int[][] dp = new int[sz][sz];
            int[][] max_first = new int[7][sz];
            int[][] max_second = new int[sz][7];
            for (int i = 0; i < N; i++) {
                int index = map.get(arr[i]);
                int lower = map.get(arr[i] - 1);
                int higher = map.get(arr[i] + 1);
                dp[index][index] = Math.max(dp[index][index], max_second[index][arr[i] % 7] + 1);
                dp[index][index] = Math.max(dp[index][index], max_first[arr[i] % 7][index] + 1);
                if (lower != -1) {
                    dp[index][index] = Math.max(dp[index][index], Math.max(dp[index][lower], dp[lower][index]) + 1);
                }
                if (higher != -1) {
                    dp[index][index] = Math.max(dp[index][index], Math.max(dp[index][higher], dp[higher][index]) + 1);
                }
                max_first[arr[i] % 7][index] = dp[index][index];
                max_second[index][arr[i] % 7] = dp[index][index];
                for (int j = 0; j < sz; j++) {
                    if (j == index) {
                        continue;
                    }
                    if (lower != -1) {
                        dp[index][j] = Math.max(dp[index][j], dp[lower][j] + 1);
                    }
                    if (higher != -1) {
                        dp[index][j] = Math.max(dp[index][j], dp[higher][j] + 1);
                    }
                    dp[index][j] = Math.max(dp[index][j], max_first[arr[i] % 7][j] + 1);
                    max_first[arr[i] % 7][j] = dp[index][j];
                    max_second[index][mapping.get(j) % 7] = Math.max(max_second[index][mapping.get(j) % 7], dp[index][j]);
                }
                for (int j = 0; j < sz; j++) {
                    if (j == index) {
                        continue;
                    }
                    if (lower != -1) {
                        dp[j][index] = Math.max(dp[j][index], dp[j][lower] + 1);
                    }
                    if (higher != -1) {
                        dp[j][index] = Math.max(dp[j][index], dp[j][higher] + 1);
                    }
                    dp[j][index] = Math.max(dp[index][j], max_second[j][arr[i] % 7] + 1);
                    max_second[j][arr[i] % 7] = dp[index][j];
                    max_first[mapping.get(j) % 7][index] = Math.max(max_first[mapping.get(j) % 7][index], dp[index][j]);
                }
            }
            int res = 0;
            for (int i = 0; i < sz; i++) {
                for (int j = 0; j < sz; j++) {
                    res = Math.max(dp[i][j], res);
                }
            }
            out.println(res);
        }

