				if (idxOne == -1)
					nxtIdx = idxTwo;
				else if (idxTwo == -1)
					nxtIdx = idxOne;
				else if (idxOne < idxTwo)
					nxtIdx = idxOne;
				else
					nxtIdx = idxTwo;

				idx = nxtIdx;
				if (idx == -1)
					break;
				if (a[idx] == 1)
					oneWins++;
				else
					twoWins++;
				int onesInCurrentSet = pre[0][idx] - (prevIdx == -1 ? 0 : pre[0][prevIdx]),
						twosInCurrentSet = pre[1][idx] - (prevIdx == -1 ? 0 : pre[1][prevIdx]);
				if ((a[idx] == 1 && (onesInCurrentSet > t || onesInCurrentSet <= twosInCurrentSet))
						|| a[idx] == 2 && (twosInCurrentSet > t || twosInCurrentSet <= onesInCurrentSet))
					break;
			}

			if (prevIdx == N - 1)
				if (oneWins > twoWins && a[N - 1] == 1)
					ans.add(new Pair(oneWins, t));
				else if (twoWins > oneWins && a[N - 1] == 2)
					ans.add(new Pair(twoWins, t));
		}

		Collections.sort(ans);
		out.println(ans.size());
		for (int i = 0, sz = ans.size(); i < sz; ++i) {
			Pair cur = ans.get(i);
			out.println(cur.s + " " + cur.t);
		}
		out.flush();
		out.close();

	}

public static void main(String[] args) throws IOException{
    	BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
    	PrintWriter out = new PrintWriter(System.out);
    	String[] line=  in.readLine().split(" ");
    	int n = Integer.parseInt(line[0]);
    	int m = Integer.parseInt(line[1]);
    	int[] dp = new int[n];
    	for(int i = 0; i<n; i++) {
    		dp[i] = n-1;
    	}
    	ArrayList<Integer>[] adj = new ArrayList[n];
    	for(int i = 0; i<n; i++) {
    		adj[i] = new ArrayList<Integer>();
    	}
    	for(int i = 0; i<m; i++) {
    		line = in.readLine().split(" ");
    		int a = Integer.parseInt(line[0])-1;
    		int b = Integer.parseInt(line[1])-1;
    		adj[a].add(b);
    		adj[b].add(a);
    	}
    	for(int i = 0; i<n; i++) {
    		Collections.sort(adj[i]);
    	}
    	Node[] ar = new Node[n];
    	for(int i = 0; i<n; i++) {
    		ar[i] = new Node();
    	}
    	int p1 = 0;
    	int p2 = 0;
    	while(p1<n) {
    		while(p2+1<n) {
    			p2++;
    			for(int j = 0; j<adj[p2].size(); j++) {
    				int v = adj[p2].get(j);
    				if(v>p2 || v<p1) {
    					continue;
    				}
    				while(connected(ar[p2],ar[v])) {
    					dp[p1] = p2-1;
    					for(int k = 0; k<adj[p1].size(); k++) {
    		    			int v2 = adj[p1].get(k);
    		    			if(connected(ar[p1],ar[v2])) {
    		    				cut(ar[p1],ar[v2]);
    		    			}
    		    		}
    					p1++;
    				}
					link(ar[p2],ar[v]);
    			}
    		}
    		dp[p1] = p2;
    		p1++;
    	}
    	long[] cumudp = new long[n+1];
    	long[] cumuind = new long[n+1];
    	for(int i = 1; i<=n; i++) {
    		cumudp[i] = cumudp[i-1]+(long)dp[i-1];
    		cumuind[i] = cumuind[i-1]+(long)(i-1);
    	}
    	int q = Integer.parseInt(in.readLine());
    	for(int z = 0; z<q; z++) {
    		line = in.readLine().split(" ");
    		int l = Integer.parseInt(line[0])-1;
    		int r = Integer.parseInt(line[1])-1;
    		if(dp[l]>r) {
    			long ans = (long)(r+1)*(long)(r-l+1)-(cumuind[r+1]-cumuind[l]);
    			out.println(ans);
    		}
    		else {
    			int low = l;
    			int high = r;
    			while(low<high) {
    				int mid = (low+high+1)/2;
    				if(dp[mid]<=r) {
    					low = mid;
    				}
    				else {
    					high = mid-1;
    				}
    			}
    			int mid = low+1;
    			long ans = 0L;
    			if(mid<=r) {
    				ans += (long)(r+1)*(long)(r-mid+1)-(cumuind[r+1]-cumuind[mid]);
    			}
    			ans += (cumudp[low+1]-cumudp[l])+(long)(low-l+1)-(cumuind[low+1]-cumuind[l]);
    			out.println(ans);
    		}
    	}
    	out.flush();
    }

