        int i,j,k;
        String res = "";

        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());

        long N = Long.parseLong(st.nextToken());        
        long K = Long.parseLong(st.nextToken());        
        int P = Integer.parseInt(st.nextToken());       

        long PN = N;

        long queries[] = new long[P];

        for (i=0;i<P;i++) {
            queries[i] = Long.parseLong(br.readLine());
        }

        if (K == 1) {
            for (i=0;i<P;i++) {
                if (queries[i] < N) {
                    res += '.';
                } else {
                    res += 'X';
                }
            }
            System.out.println(res);
            return;
        }

        if (K == 0) {
            for (i=0;i<P;i++) {
                res += '.';
            }
            System.out.println(res);
            return;
        }

        long empty = N-K;

        long div = N/2;

        char answer[] = new char[P];

        if (K <= div) {

            if (N%2 == 0) {


                long blanks = N-(K*2-1);

                for (i=0;i<P;i++) {
                    if (queries[i] <= blanks) {
                        answer[i] = '.';
                    } else {
                        if (queries[i]%2 == 0) {
                            answer[i] = 'X';
                        } else {
                            answer[i] = '.';
                        }
                    }
                }

            } else {

                N--;
                K--;

                long blanks = N-(K*2-1);

                if (N == 0)
                    blanks = 0;



                for (i=0;i<P;i++) {

                    if (queries[i] == PN) {
                        answer[i] = 'X';
                        continue;
                    }

                    if (queries[i] <= blanks) {
                        answer[i] = '.';
                    } else {
                        if (queries[i]%2 == 0) {
                            answer[i] = 'X';
                        } else {
                            answer[i] = '.';
                        }
                    }
                }
            }

        } else {
            long sequence = empty*2;

            for (i=0;i<P;i++) {
                if (queries[i] <= sequence) {

                    if (queries[i]%2 == 0) {
                        answer[i] = 'X';
                    } else {
                        answer[i] = '.';
                    }

                } else {
                    answer[i] = 'X';
                }
            }

        }

        for (i=0;i<P;i++) {
            res += answer[i];
        }

        System.out.println(res);

    }

