    		acount =  acount -  aone.get(i).slice;
    		ans = ans + aone.get(i).slice*aone.get(i).a;
    		i++;
    	}
    	if(acount != 0){
    		ans = ans + acount*aone.get(i).a;
    		aone.get(i).slice = aone.get(i).slice  - acount;
    	}

    	int  j =0;
