    		bcount =  bcount -  bone.get(j).slice;
    		ans = ans + bone.get(j).slice*bone.get(j).b;
    		j++;
    	}
    	if(bcount != 0){
    		ans = ans + bcount*bone.get(j).b;
    		bone.get(j).slice = bone.get(j).slice  - bcount;
    	}

    	long amax = 0;
    	long bmax = 0;
