    		amax = amax + aone.get(i).slice*aone.get(i).a;
    		bmax = bmax + aone.get(i).slice*aone.get(i).b;
    	}
    	for(;j<bone.size();j++){
    		amax = amax + bone.get(j).slice*bone.get(j).a;
    		bmax = bmax + bone.get(j).slice*bone.get(j).b;
    	}
