public static void main(String[] args) throws IOException {
		BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
		PrintWriter out = new PrintWriter(System.out);

		int n = Integer.valueOf(in.readLine());
		int[] a = new int[n];
		String[] ai = in.readLine().split(" ");
		for (int i = 0 ; i < n ; i++) {
			a[i] = Integer.valueOf(ai[i]);
		}

		int m = Integer.valueOf(in.readLine());
		int[][] queries = new int[m][];
		for (int i = 0 ; i < m ; i++) {
			String[] qdata = in.readLine().split(" ");
			int len = qdata.length;
			queries[i] = new int[len];
			for (int j = 0 ; j < len ; j++) {
				queries[i][j] = Integer.valueOf(qdata[j]);
			}
		}

		int BUCKET_SIZE = 200;
		int BUCKET_LENGTH = (n + BUCKET_SIZE - 1) / BUCKET_SIZE;
		int[] reversed = new int[BUCKET_LENGTH];
		int[] ones = new int[BUCKET_LENGTH];
		int[] bleft = new int[BUCKET_LENGTH];
		int[] bright = new int[BUCKET_LENGTH];
		int[] state = new int[n];
		long[] answer = new long[m];
		for (int b = 0 ; b < 20 ; b++) {
			long base = (long)Math.pow(2L, b);
			Arrays.fill(reversed, 0);
			Arrays.fill(ones, 0);
			Arrays.fill(state, 0);
			for (int i = 0 ; i < BUCKET_LENGTH ; i++) {
				bleft[i] = i * BUCKET_SIZE;
				bright[i] = Math.min((i+1) * BUCKET_SIZE, n);
				for (int j = bleft[i] ; j < bright[i] ; j++) {
					if ((a[j] & (1<<b)) >= 1) {
						state[j] = 1;
						ones[i]++;
					}
				}
			}
			for (int q = 0 ; q < m ; q++) {
				int l = queries[q][1] - 1;
				int r = queries[q][2] - 1;
				int leftB = l / BUCKET_SIZE;
				int rightB = r / BUCKET_SIZE;
				if (queries[q][0] == 1) {
					long cnt = 0;
					if (leftB < rightB) {

						for (int i = l ; i < bright[leftB] ; i++) {
							if (((state[i] + reversed[leftB]) & 1) == 1) {
								cnt++;
							}
						}


						for (int i = bleft[rightB] ; i <= r ; i++) {
							if (((state[i] + reversed[rightB]) & 1) == 1) {
								cnt++;
							}
						}


						for (int B = leftB + 1 ; B < rightB ; B++) {
							cnt += ones[B];
						}
					} else {

						for (int i = l ; i <= r ; i++) {
							if (((state[i] + reversed[leftB]) & 1) == 1) {
								cnt++;
							}
						}
					}
					answer[q] += cnt * base;
				} else if ((queries[q][3] & (1<<b)) >= 1){

					ones[leftB] = 0;
					for (int i = bleft[leftB] ; i < bright[leftB] ; i++) {
						state[i] = (state[i] + reversed[leftB] + ((l <= i && i <= r) ? 1 : 0)) & 1;
						ones[leftB] += state[i];
					}
					reversed[leftB] = 0;


					if (leftB == rightB) {
						continue;
					}


					ones[rightB] = 0;
					for (int i = bleft[rightB] ; i < bright[rightB] ; i++) {
						state[i] = (state[i] + reversed[rightB] + ((l <= i && i <= r) ? 1 : 0)) & 1;
						ones[rightB] += state[i];
					}
					reversed[rightB] = 0;


					for (int B = leftB + 1 ; B < rightB ; B++) {
						ones[B] = (bright[B] - bleft[B]) - ones[B];
						reversed[B] = (reversed[B] + 1) & 1;
					}
				}
			}


		}





		for (int i = 0 ; i < m ; i++) {
			if (queries[i][0] == 1) {
				out.println(answer[i]);
			}
		}
		out.flush();
	}

