		Reader.init(System.in);
		PrintWriter out=new PrintWriter(System.out);
		int n=Reader.nextInt(),q=Reader.nextInt();
		LinkedList<Integer> ll=new LinkedList<Integer>();
		NoD[] query=new NoD[q];
		for(int i=0;i<n;i++) {
			ll.addLast(Reader.nextInt());
		}
		for(int i=0;i<q;i++) {
			query[i]=new NoD(Reader.nextLong(),i);
		}
		Arrays.sort(query,new Comparator<NoD>() {
			public int compare(NoD a, NoD b) {
				return Long.compare(a.a, b.a);
			}
		});
		int operations=0;
		int[] arr=new int[n];
		int[][] ans=new int[q][2];
		for(NoD a:query) {
			long v=a.a-operations;
			if(operations<n-1) {
				if(v==1) {
					int aa=ll.pollFirst();
					int b=ll.peekFirst();
					ll.addFirst(aa);
					ans[a.b][0]=aa;ans[a.b][1]=b;
				}
				else {
					while(v!=1 && operations<n-1) {
						operations++;
						v--;
						int aa=ll.pollFirst();
						int bb=ll.pollFirst();
						if(aa>bb) {
							ll.addFirst(aa);ll.addLast(bb);
						}
						else {
							ll.addLast(aa);ll.addFirst(bb);
						}
					}
					if(operations==n-1) {
						for(int i=0;i<n;i++) {
							arr[i]=ll.pollFirst();
						}
						int el=(int)(v%(n-1));
						if(el==0) el=n-1;
						ans[a.b][0]=arr[0];
						ans[a.b][1]=arr[el];

					}
					else {
						int aa=ll.pollFirst();
						int b=ll.peekFirst();
						ll.addFirst(aa);
						ans[a.b][0]=aa;ans[a.b][1]=b;
					}
				}
			}
			else {
				int el=(int)(v%(n-1));
				if(el==0) el=n-1;
				ans[a.b][0]=arr[0];
				ans[a.b][1]=arr[el];
			}
		}
		for(int i=0;i<q;i++) {
			out.println(ans[i][0]+" "+ans[i][1]);
		}

		out.flush();

	}

