	private void run() throws IOException {
		Scanner scanner = new Scanner(System.in);
		loop: while (true) {
			int n = scanner.nextInt();
			if (n == 0)
				break;
			Map<String, Integer>[] supers = new Map[n];
			for (int i = 0; i < n; i++)
				supers[i] = new HashMap<String, Integer>();
			Map<String, Integer> min = new HashMap<String, Integer>();
			for (int i = 0; i < n; i++) {
				int k = scanner.nextInt();
				for (int j = 0; j < k; j++) {
					String name = scanner.next();
					int value = scanner.nextInt();
					supers[i].put(name, value);
					if (!min.containsKey(name) || min.get(name) > value)
						min.put(name, value);
				}
			}
			int q = scanner.nextInt();
			String[] name = new String[q];
			for (int i = 0; i < q; i++)
				name[i] = scanner.next();
			int m = scanner.nextInt();
			List<Point>[] lists = new List[n + 1];
			for (int i = 0; i <= n; i++)
				lists[i] = new ArrayList<Main.Point>();

			while (m-- > 0) {
				int s = scanner.nextInt();
				int t = scanner.nextInt();
				int d = scanner.nextInt();
				lists[s].add(new Point(t, d));
				lists[t].add(new Point(s, d));
			}
			int sum = 0;
			for (int i = 0; i < q; i++) {
				if (!min.containsKey(name[i])) {
					System.out.println("impossible");
					continue loop;
				}
				sum += min.get(name[i]);
			}
			int[][] dp = new int[n + 1][1 << q];
			for (int[] dp1 : dp)
				Arrays.fill(dp1, 1 << 20);
			PriorityQueue<Point> pq = new PriorityQueue<Point>();
			pq.offer(new Point(0, 0, 0));
			int ans = 0;
			int[] bits = new int[n];
			for (int i = 0; i < n; i++) {
				int bit = 0;
				for (int j = 0; j < q; j++) {
					if (supers[i].containsKey(name[j])
							&& supers[i].get(name[j]).equals(min.get(name[j])))
						bit |= 1 << j;
				}
				bits[i] = bit;
			}
			while (!pq.isEmpty()) {
				Point p = pq.poll();
				int t = p.t;
				int cost = p.cost;
				int bit = p.bit;
				if (t == 0 && bit == (1 << q) - 1) {
					ans = cost;
					break;
				}
				if (dp[t][bit] < cost)
					continue;
				dp[t][bit] = cost;
				if (t > 0)
					bit |= bits[t - 1];
				for (Point point : lists[t])
					pq.offer(new Point(point.t, cost + point.cost, bit));

			}
			System.out.println(sum + " " + ans);
		}
	}

void solve(FastScanner in) {
		int N = in.nextInt();

		List<List<Integer>> player = new ArrayList<List<Integer>>(N+1);
		for(int i=0;i<=N;i++) {
			player.add(new ArrayList<Integer>(N-1));
		}
		for(int i=1;i<=N;i++) {
			List<Integer> p = player.get(i);
			for(int j=0;j<N-1;j++) {
				p.add(in.nextInt());
			}
			Collections.reverse(p);
		}

		PriorityQueue<Integer> PlanOp = new PriorityQueue <Integer>(N);
		List<Integer> AddL = new ArrayList<Integer>(N);
		Iterator<Integer> iterator;
		int []Listlen = new int[N+1]; 
		boolean []yo_f = new boolean[N+1]; 
		int []op = new int[N+1]; 
		Arrays.fill(Listlen, N-1);
		Arrays.fill(op, -1);

		boolean Compete_f = false; 
		int Opponent;
		int Days = 0;

		for(int i=1;i<=N;i++) {
			op[i] = player.get(i).get(0); 
			PlanOp.add(i);
		}
		while(true) {
			Compete_f = false;

			while(PlanOp.size()>0) {
				int i = PlanOp.poll();
				yo_f[i] = true; 
				if(Listlen[i] <= 0)continue;    
				Opponent = op[i];
				if(Opponent == -1 || yo_f[Opponent]) continue; 
				if(op[Opponent] == i) { 


					op[Opponent] = -1; 
					op[i] = -1;
					yo_f[Opponent] = true; 
					player.get(i).remove(0);
					player.get(Opponent).remove(0);
					Listlen[i]--;
					Listlen[Opponent]--;
					Compete_f = true;

					if(Listlen[i]>0 && op[i] == -1) {
						AddL.add(i);
					}

					if(Listlen[Opponent]>0 && op[Opponent] == -1) {
						AddL.add(Opponent);
					}
				}
			}

			if(!Compete_f) {
				for(int i=1;i<=N;i++) {
					if(Listlen[i]>0) {
						Days = -1;
						break;
					}
				}
				break;
			}

			if(Compete_f) {
				iterator = AddL.iterator();
				while (iterator.hasNext()) {
				    int i = iterator.next();
				    op[i] = player.get(i).get(0);
				    PlanOp.add(i);
				}
				AddL.clear();
			}

			Arrays.fill(yo_f, false);
			Days++;
		}

		System.out.println(Days);
	}

public static void main(String[] args) throws IOException {
        FastScanner sc=new FastScanner();
        int N = sc.nextInt();
        int K = sc.nextInt();
        int[] coefs = new int[N+1];
        for (int i = 0; i <= N; i++)
        	coefs[i] = sc.nextInt();
        int[] base2pos = new int[N+33];
        int[] base2neg = new int[N+33];
        for (int i = 0; i <= N; i++) {
        	boolean neg = false;
        	if (coefs[i] > 0) {
        		int c = coefs[i];
        		int pow = (int)(Math.log(c)/Math.log(2));
        		while (c > 0) {
        			if ((int)Math.pow(2,pow) <= c) {
            			base2pos[i+pow] += 1;
            			c -= (int)Math.pow(2,pow);
        			}
        			pow--;
        		}
        	} else {
        		int c = Math.abs(coefs[i]);
        		int pow = (int)(Math.log(c)/Math.log(2));
        		while (c > 0) {
        			if ((int)Math.pow(2,pow) <= c) {
            			base2neg[i+pow] += 1;
            			c -= (int)Math.pow(2,pow);
        			}
        			pow--;
        		}
        	}
        }

        for (int i = 0; i <= N+31; i++) {
        	base2pos[i+1] += base2pos[i]/2;
        	base2pos[i] = base2pos[i] % 2;
        }

        for (int i = 0; i <= N+31; i++) {
        	base2neg[i+1] += base2neg[i]/2;
        	base2neg[i] = base2neg[i] % 2;
        }

        boolean positive = true;
        int index = N+32;
        while (base2pos[index] == base2neg[index]) {
        	index--;
        }
        if (base2neg[index] == 1) positive = false;

        int matches = 0;
        if (positive) {
        	int[] ans = subtract(base2pos,base2neg,N);
        	int first1 = -1;
        	int last1 = -1;
        	for (int i = 0; i <= N+32; i++) {
        		if (ans[i] == 1) {
        			first1 = i;
        			break;
        		}
        	}
        	for (int i = N+32; i >= 0; i--) {
        		if (ans[i] == 1) {
        			last1 = i;
        			break;
        		}
        	}
        	for (int i = 0; i <= Math.min(N, first1); i++) {
        		int reduce = K + coefs[i];
        		int powReduce = (int)(Math.log(reduce)/Math.log(2));
        		if (powReduce+i >= last1) {
        			long num = 0;
        			for (int j = 0; j <= last1-i; j++) {
        				num += ans[j+i]*((int)Math.pow(2, j));
        			}
        			if (reduce >= num) {
        				if (i == N && coefs[i]==num) {
        					continue;
        				}
        				matches++;
        			}
        		}
        	}
        } else {
        	int[] ans = subtract(base2neg,base2pos,N);

        	int first1 = -1;
        	int last1 = -1;
        	for (int i = 0; i <= N+32; i++) {
        		if (ans[i] == 1) {
        			first1 = i;
        			break;
        		}
        	}
        	for (int i = N+32; i >= 0; i--) {
        		if (ans[i] == 1) {
        			last1 = i;
        			break;
        		}
        	}
        	for (int i = 0; i <= Math.min(N, first1); i++) {
        		int reduce = K - coefs[i];
        		int powReduce = (int)(Math.log(reduce)/Math.log(2));
        		if (powReduce+i >= last1) {
        			long num = 0;
        			for (int j = 0; j <= last1-i; j++) {
        				num += ans[j+i]*((int)Math.pow(2, j));
        			}
        			if (reduce >= num) {
        				if (i == N && coefs[i]==num) {
        					continue;
        				}
        				matches++;
        			}
        		}
        	}
        }
        System.out.println(matches);
    }

