boolean solve() throws IOException {
      String line = in.readLine();
      if (line == null) {
        return false;
      }
      if (line.isEmpty()) {
        return true;
      }
      StringTokenizer tok = new StringTokenizer(line);
      int n = Integer.parseInt(tok.nextToken());
      int q = Integer.parseInt(tok.nextToken());
      int[] a = new int[n];
      tok = new StringTokenizer(in.readLine());
      Deque<Integer> deque = new ArrayDeque<>();
      List<Integer> finalDeq = null;
      ArrayList<Pair> requests = new ArrayList<>();
      Map<Integer, Integer> ansA = new TreeMap<>();
      Map<Integer, Integer> ansB = new TreeMap<>();
      int maxVal = -1;
      int maxind = -1;
      for (int i = 0; i < n; ++i){
        a[i] = Integer.parseInt(tok.nextToken());
        deque.addLast(a[i]);
        if (maxVal < a[i]) {
          maxVal = a[i];
          maxind = i;
        }
      }

      for (int qq = 0; qq < q; ++qq) {
        long m = Long.parseLong(in.readLine());
        requests.add(new Pair(qq, m));
      }

      Collections.sort(requests,  (p1, p2) -> Long.compare(p1.value, p2.value));
      int lastPerm = 0;
      int lastA = -1;
      int lastB = -1;
      for (int i = 0; i < requests.size(); ++i) {
        Pair req  = requests.get(i);
        if (req.value <= maxind) {
          if (lastPerm == req.value) {
            ansA.put(req.index, lastA);
            ansB.put(req.index, lastB);
          } else while (lastPerm < req.value) {
            ++lastPerm;
            int A = deque.pollFirst();
            int B = deque.pollFirst();
            lastA = A;
            lastB = B;
            ansA.put(req.index, A);
            ansB.put(req.index, B);
            if (A > B) {
              deque.addFirst(A);
              deque.addLast(B);
            } else {
              deque.addFirst(B);
              deque.addLast(A);
            }
          }

        } else {
          while (lastPerm < maxind) {
            ++lastPerm;
            int A = deque.pollFirst();
            int B = deque.pollFirst();
            ansA.put(req.index, A);
            ansB.put(req.index, B);
            if (A > B) {
              deque.addFirst(A);
              deque.addLast(B);
            } else {
              deque.addFirst(B);
              deque.addLast(A);
            }
          }
          if (finalDeq== null) {
            finalDeq = new ArrayList<>();
            for (Integer aa : deque) {
              finalDeq.add(aa);
            }
          }
          assert lastPerm == maxind;
          int left =(int) ((req.value - (1L +  maxind)) % ((long) (n - 1)));
          int b = finalDeq.get(1 + left);

          ansA.put(req.index, finalDeq.get(0));
          ansB.put(req.index, b);
        }
      }

      for (Integer key : ansA.keySet()) {
        int A = ansA.get(key);
        int B = ansB.get(key);
        out.println(A + " " + B);
      }


      return true;
    }

public static void main(String[] args) {
		Scanner in = new Scanner(System.in);
		int n = in.nextInt(), t = in.nextInt();
		adj = new ArrayList[n];
		for(int i = 1; i < n; i++) {
			int a = in.nextInt()-1, b = in.nextInt()-1;
			if(adj[a] == null)
				adj[a] = new ArrayList<Integer>();
			if(adj[b] == null)
				adj[b] = new ArrayList<Integer>();
			adj[a].add(b);
			adj[b].add(a);
		}


		if(adj[0] == null)
			adj[0] = new ArrayList<Integer>();

		relevant = new boolean[n];
		visited = new boolean[n];
		int root = in.nextInt()-1;
		relevant[root] = true;
		for(int i = 1; i < t; i++)
			relevant[in.nextInt()-1] = true;

		Stack<Integer> rel = new Stack<Integer>();
		rel.add(root);
		int[] adjInd = new int[n];
		visited[root] = true;
		while(!rel.isEmpty()) {
			Integer v = rel.peek();
			if(adjInd[v] < adj[v].size()) {
				int i = adj[v].get(adjInd[v]++);
				if(!visited[i]) {
					visited[i] = true;
					rel.push(i);
				}
			}
			else {
				rel.pop();
				if(!rel.empty())
					relevant[rel.peek()] |= relevant[v];

			}
		}

		int count = 0;
		for(int i = 0; i < n; i++) {
			if(relevant[i]) {
				count++;
				visited[i] = false;
			}
		}


		Queue<Integer> q = new LinkedList<Integer>();
		q.offer(root);
		int next = root;
		visited[root] = true;
		while(!q.isEmpty()) {
			next = q.poll();
			for(Integer i : adj[next]) {
				if(relevant[i] && !visited[i]) {
					visited[i] = true;
					q.offer(i);
				}
			}
		}

		int minEndpoint = next;
		int diameter = 0;

		Stack<MaxDepth> stack = new Stack<MaxDepth>();
		stack.push(new MaxDepth(next, 0));
		visited[next] = false;
		while(!stack.isEmpty()) {
			MaxDepth frame = stack.peek();
			if(frame.adjVisited < adj[frame.v].size()) {
				int i = adj[frame.v].get(frame.adjVisited++);
				if(relevant[i] && visited[i]) {
					stack.push(new MaxDepth(i, frame.depth+1));
					visited[i] = false;
				}
			}
			else {
				stack.pop();
				int depth2 = frame.depth * 2;
				if(depth2 == frame.max)
					center1 = frame.v;
				else if(depth2-1 == frame.max)
					center1 = frame.v;
				else if(depth2+1 == frame.max)
					center2 = frame.v;

				if(!stack.empty())
					stack.peek().updateMax(frame.max);
				else
					diameter = frame.max;
			}
		}

		int[] dist = new int[n];

		q.offer(center1);
		visited[center1] = true;
		while(!q.isEmpty()) {
			next = q.poll();
			if(dist[next] == diameter/2)
				if(next < minEndpoint)
					minEndpoint = next;
			for(Integer i : adj[next]) {
				if(relevant[i] && !visited[i] && i != center2) {
					visited[i] = true;
					dist[i] = 1 + dist[next];
					q.offer(i);
				}
			}
		}
		if(center2 != -1) {
			q.offer(center2);
			visited[center2] = true;
			while(!q.isEmpty()) {
				next = q.poll();
				if(dist[next] == diameter/2)
					if(next < minEndpoint)
						minEndpoint = next;
				for(Integer i : adj[next])
					if(relevant[i] && !visited[i]) {
						visited[i] = true;
						dist[i] = 1 + dist[next];
						q.offer(i);
					}
			}
		}

		System.out.println(minEndpoint+1);
		System.out.println(diameter + 2 * (count - diameter - 1));
	}

