void work() {
		n=ni();m=ni();
		if(m==1) {
			out.println(1);
			return;
		}
		map=new HashMap<>();
		graph=new long[m];
		int cur=0;
		for(int i=0;i<n;i++) {
			ArrayList<Integer> list=new ArrayList<>();
			HashSet<String> set=new HashSet<>();
			while(i<n&&ni()==2) {
				String str=ns();
				if(!set.contains(str)) {
					set.add(str);
					if(!map.containsKey(str)) {
						map.put(str, cur++);
					}
					list.add(map.get(str));
				}
				i++;
			}
			for(int j=0;j<list.size();j++) {
				for(int k=j+1;k<list.size();k++) {
					int s=list.get(j);
					int e=list.get(k);
					graph[s]|=1L<<e;
					graph[e]|=1L<<s;
				}
			}
		}
		for(int i=0;i<m;i++) {
			graph[i]=(1L<<m)-1-graph[i]-(1L<<i);
		}
		int len1=m/2;
		int len2=m-m/2;
		dp1=new long[1<<len1];
		dp2=new long[1<<len2];
		rec1=new long[len1];
		rec3=new long[len1];
		rec2=new long[len2];
		for(int i=0;i<len1;i++) {
			rec1[i]=graph[i]&((1L<<len1)-1);
			long mask=graph[i]>>len1;
			rec3[i]=mask;
		}
		for(int i=0;i<len2;i++) {
			long mask=graph[i+len1]>>len1;
			rec2[i]=mask;
		}
		Arrays.fill(dp1,-1);
		Arrays.fill(dp2,-1);
		dp1[0]=0;
		dp2[0]=0;
		for(int i=0;i<1<<len1;i++) {
			if(dp1[0]!=-1) {
				for(int j=0;j<len1;j++) {
					if((i&(1<<j))==0) {
						int k=i|(1<<j);
						long mask=rec1[j];
						if((mask|i)==mask) {
							dp1[k]=dp1[i]+1;
						}
					}
				}
			}
		}
		for(int i=0;i<1<<len2;i++) {
			if(dp2[0]!=-1) {
				for(int j=0;j<len2;j++) {
					if((i&(1<<j))==0) {
						int k=i|(1<<j);
						long mask=rec2[j];
						if((mask|i)==mask) {
							dp2[k]=dp2[i]+1;
						}
					}
				}
			}
		}
		for(int i=0;i<1<<len2;i++) {
			for(int j=0;j<len2;j++) {
				if((i&(1<<j))>0) {
					int pre=i-(1<<j);
					dp2[i]=Math.max(dp2[i], dp2[pre]);
				}
			}
		}
		long ret=0;
		for(int i=0;i<1<<len1;i++) {
			if(dp1[i]==-1)continue;
			long mask=(1<<len2)-1;
			for(int j=0;j<len1;j++) {
				if((i&(1<<j))>0) {
					mask&=rec3[j];
				}
			}
			ret=Math.max(ret, dp1[i]+dp2[(int)mask]);
		}
		out.println(ret);
	}

