public static void main(String[] args)
	{
		Scanner in = new Scanner(System.in);

		int r = in.nextInt();
		int c = in.nextInt();
		int n = in.nextInt();
		int k = in.nextInt();

		Viola[] violas = new Viola[n];
		for(int x = 0; x < n; x++)
		{
			violas[x] = new Viola(in.nextInt() - 1, in.nextInt() - 1);
		}

		Arrays.sort(violas);

		int[] column = new int[n + 2];
		for(int y = 0; y < violas.length; y++)
		{
			violas[y].index = y + 1;
			column[y + 1] = violas[y].col;
		}

		column[0] = -1;
		column[n + 1] = c;

		Arrays.sort(violas, new CompareRow());

		int index = 0;
		long result = 0;
		for(int z = 0; z < r; z++)
		{
			while(index < violas.length && violas[index].row == z)
			{
				index++;
			}

			ArrayList<Viola> list = new ArrayList<Viola>();
			for(int a = 0; a < index; a++)
			{
				list.add(violas[a]);
			}

			Collections.sort(list);

			int[] left = new int[n + 2];
			int[] right = new int[n + 2];
			int[] side = new int[n + 2];
			long[] count = new long[n + 2];
			long total = 0;
			for(int b = 0; b < list.size(); b++)
			{
				int current = list.get(b).index;
				int li = b == 0 ? 0 : list.get(b - 1).index;
				int ri = b == list.size() - 1 ? n + 1 : list.get(b + 1).index;

				left[current] = li;
				right[li] = current;
				right[current] = ri;
				left[ri] = current;
			}

			for(int d = 0; d < list.size(); d++)
			{
				int current = list.get(d).index;

				if(d + k - 1 < list.size())
				{
					side[current] = list.get(d + k - 1).index;
				}
				else
				{
					side[current] = n + 1;
				}

				count[current] = (column[current] - column[left[current]]) * (c - column[side[current]]);
				total += count[current];
			}

			int i = 0;
			for(int e = 0; e <= z; e++)
			{
				result += total;

				while(i < violas.length && violas[i].row == e)
				{
					int current = violas[i].index;

					total -= count[current];

					left[right[current]] = left[current];
					right[left[current]] = right[current];

					if(right[current] <= n)
					{
						total -= count[right[current]];
						int node = right[current];
						count[right[current]] = (column[node] - column[left[node]]) * (c - column[side[node]]);
						total += count[right[current]];
					}

					int node = left[current];
					for(int f = 0; f < k - 1; f++)
					{
						if(node == 0)
						{
							break;
						}

						total -= count[node];

						if(side[node] <= n)
						{
							side[node] = right[side[node]];
						}

						count[node] = (column[node] - column[left[node]]) * (c - column[side[node]]);

						total += count[node];

						node = left[node];
					}

					i++;
				}
			}
		}

		System.out.println(result);
	}

