		{
			Collections.sort(arr[i], Collections.reverseOrder());
		}

		long[] DP = new long[K + 1];

		Curve[] preCurve = new Curve[K + 1];

		for (int s = 0; s < arr.length; s++) 
		{
			if (arr[s].size() > 0)
			{
				int L = arr[s].size();

				long[] sum = new long[L];

				for (int i=0; i < L; i++)
				{
					sum[i] = arr[s].get(i);
				}


				for (int i = 1 ; i < L; i++)
					sum[i] += sum[i - 1];


				Curve.sum = sum;


				for (int x = 0; x < s; x++)
				{
					int curr = K - x, j = 1, frontPointer = 0, backPointer = 0;
					for (int i=0; curr- i * s >=0; i++)
					{

						while (backPointer-frontPointer > 0 && preCurve[frontPointer].a <= i)
							frontPointer++;

						while (j - i <= L && (curr - j * s) >= 0)
						{
							int pos = curr - j * s;
							Curve nc = new Curve(j, i, DP[pos]);

							if (frontPointer < backPointer)
							{
								preCurve[backPointer-1].t = nc.ot(preCurve[backPointer - 1]);
							}


							while (backPointer-frontPointer > 1 && preCurve[backPointer -1].t <= preCurve[backPointer - 2].t)
							{
								backPointer--;

								preCurve[backPointer-1].t = nc.ot(preCurve[backPointer - 1]);
							}

							preCurve[backPointer++] = nc;
							j++;
						}



						while (backPointer-frontPointer > 1 && preCurve[frontPointer].f(i) <= preCurve[frontPointer+1].f(i))
							frontPointer++;

						if (frontPointer < backPointer)
						{
							int pos = curr - i * s;

							DP[pos] = Math.max(DP[pos], preCurve[frontPointer].f(i));
						}
					}
				}
			}
		}

		long ans = 0;
		for (int i = 1; i <= K; i++)
			ans = Math.max(ans, DP[i]);
		System.out.println(ans);
	}

static void go() {
        int n = in.nextInt();
        int[] a = in.nextIntArray(n);



        int[][] score = new int[n][2];
        int[][] map = new int[100001][2];
        int winner = a[n - 1] - 1;
        int loser = 1 - winner;
        score[0][a[0] - 1] = 1;
        map[1][a[0] - 1] = 1;
        for (int i = 1; i < n; i++) {
            int j = a[i] - 1;
            score[i][j] = score[i - 1][j] + 1;
            map[score[i][j]][j] = i + 1;
            score[i][1 - j] = score[i - 1][1 - j];
        }

        ArrayList<Pair> ans = new ArrayList<>();
        int max1 = score[n - 1][winner], max2 = score[n - 1][loser];
        if (max1 > max2) {
            ans.add(new Pair(1, max1));
        }
        for (int i = max1 / 2; i >= 1; i--) {
            int index, s = 0, t1 = 0, t2 = 0;
            if (map[i][winner] < map[i][loser] || map[i][loser] == 0) {
                index = map[i][winner] - 1;
                s = score[index][winner];
                t1 = 1;
            } else {
                index = map[i][loser] - 1;
                s = score[index][loser];
                t2 = 1;
            }
            int next1, next2, i1, i2;
            while (true) {
                next1 = score[index][winner] + s;
                next2 = score[index][loser] + s;
                if (next1 > max1)
                    break;

                if (next2 > max2) {
                    if ((max1 - score[index][winner]) % s == 0) {
                        t1 += (max1 - score[index][winner]) / s;
                        if (t1 > t2) {
                            ans.add(new Pair(t1, s));
                        }
                    }
                    break;
                }

                i1 = map[next1][winner] - 1;
                i2 = map[next2][loser] - 1;
                if (i1 > i2) {
                    t2++;
                    index = i2;
                } else {
                    t1++;
                    index = i1;
                }
            }
        }

        out.println(ans.size());
        Collections.sort(ans, new Comparator<Pair>() {
            @Override
            public int compare(Pair o1, Pair o2) {
                if (o1.t == o2.t)
                    return o1.s - o2.s;
                return o1.t - o2.t;
            }
        });
        for (int i = 0; i < ans.size(); i++) {
            out.println(ans.get(i).t + " " + ans.get(i).s);
        }
    }

public void solve() throws IOException {				
		int N = nextInt();
		int[] A = new int[N];
		for (int i = 0; i < N; i++) {
			A[i] = nextInt();
		}
		Arrays.sort(A);

		if (N == 1) {
			out.println(-1);
			return;
		}
		if (N == 2) {
			if (A[0] == A[1]) {
				out.println(1);
				out.println(A[0]);
			} else {
				if ( (A[1] - A[0]) % 2 == 1) {
					out.println(2);
					out.println( (A[0] - (A[1]-A[0])) + " " + (A[1] + (A[1]-A[0])) );
				} else {
					out.println(3);
					int mid = A[0] + (A[1] - A[0])/2;					
					out.println( (A[0] - (A[1]-A[0])) + " " + mid + " " + (A[1] + (A[1]-A[0])) );
				}
			}			
			return;
		}

		int[] D = new int[N-1];
		for (int i = 1; i < N; i++) {
			D[i-1] = A[i] - A[i-1];
		}

		boolean aSame = true;
		boolean dSame = true;

		for (int i = 1; i < N; i++) {
			if (A[i] != A[i-1]) aSame = false;
		}		
		for (int i = 1; i < N-1; i++) {
			if (D[i] != D[i-1]) dSame = false;
		}

		if (aSame) {
			out.println(1);
			out.println(A[0]);
			return;
		}
		else if (dSame) {
			out.println(2);
			out.println( (A[0] - D[0]) + " " + (A[N-1] + D[0]) );
			return;
		}

		HashMap<Integer, Integer> diffs = new HashMap<Integer, Integer>();
		for (int i = 0; i < N-1; i++) {
			if (diffs.containsKey(D[i])) {
				diffs.put(D[i], diffs.get(D[i])+1);
			} else {
				diffs.put(D[i], 1);
			}
		}

		if (diffs.size() > 2) {
			out.println(0);
			return;
		}

		int smallest = Integer.MAX_VALUE/2;
		int largest = -1;
		for (int d: diffs.keySet()) {
			smallest = Math.min(d, smallest);
			largest = Math.max(d, largest);
		}

		if (diffs.get(largest) > 1) {
			out.println(0);
			return;
		}

		if (largest/2 != smallest || largest % 2 == 1) {
			out.println(0);
			return;
		}

		out.println(1);
		for (int i = 0; i < N-1; i++) {
			if (D[i] == largest) {
				out.println( A[i] + largest/2);
			}			
		}

	}

