        FastScanner fs = new FastScanner();
        int n, m, q;
        n = fs.nextInt();
        m = fs.nextInt();
        q = fs.nextInt();

        BitSet[] lines = new BitSet[q + 1];

        lines[0] = new BitSet(m + 1);
        int linesCnt = 1;

        int[][] position = new int[q + 1][n + 1];
        for (int i = 1; i <= n; ++i) {
            position[0][i] = 0;
        }

        BitSet ones = new BitSet(m + 1);
        ones.set(0, m + 1);
        int result = 0;
        int[] results = new int[q + 1];
        results[0] = 0;
        for (int l = 1; l <= q; ++l) {
            int op = fs.nextInt();

            if (op != 4) {
                for (int k = 1; k <= n; ++k) {
                    position[l][k] = position[l - 1][k];
                }

                if (op == 1) {
                    int i = fs.nextInt();
                    int j = fs.nextInt();
                    if (!lines[position[l][i]].get(j)) {
                        lines[linesCnt] = (BitSet) lines[position[l][i]].clone();
                        lines[linesCnt].set(j);
                        position[l][i] = linesCnt;
                        linesCnt++;
                        result++;
                    }
                }
                else if (op == 2) {
                    int i = fs.nextInt();
                    int j = fs.nextInt();
                    if (lines[position[l][i]].get(j)) {
                        lines[linesCnt] = (BitSet) lines[position[l][i]].clone();

                        lines[linesCnt].clear(j);


                        position[l][i] = linesCnt;
                        linesCnt++;
                        result--;
                    }
                }
                else if (op == 3) {
                    int i = fs.nextInt();

                    int before = lines[position[l][i]].cardinality();

                    int after = m - before;

                    lines[linesCnt] = (BitSet) lines[position[l][i]].clone();
                    lines[linesCnt].xor(ones);
                    lines[linesCnt].clear(0);
                    position[l][i] = linesCnt;
                    linesCnt++;
                    result += (after - before);
                }

                results[l] = result;
                System.out.println(result);
            }
            else {
                int i = fs.nextInt();

                for (int k = 1; k <= n; ++k) {
                    position[l][k] = position[i][k];
                }

                result = results[i];
                results[l] = result;
                System.out.println(results[i]);
            }
        }
    }

