        myf = new boolean[h][w];
        int[][][][] dp = new int[2][2][w][w];
        for (int row = 0; row < h; ++row) {
            int[][][][] newdp = new int[2][2][w][w];
            for (int fd = 0; fd < 2; ++fd)
                for (int ld = 0; ld < 2; ++ld)
                    for (int fc = 0; fc < w; ++fc)
                        for (int lc = fc; lc < w; ++lc) {
                            int cur = dp[fd][ld][fc][lc];
                            if (cur == 0) continue;
                            for (int newfd = fd; newfd < 2; ++newfd)
                                for (int newld = ld; newld < 2; ++newld) {
                                    int newfc; if (newfd == 0) newfc = fc;
                                    else if (fd == 0) newfc = fc + 1;
                                    else newfc = fc;
                                    int newlc;
                                    if (newld == 0) newlc = lc;
                                    else if (ld == 0) newlc = lc - 1;
                                    else newlc = lc;
                                    if (newfc > newlc) continue;
                                    int[] arr = newdp[newfd][newld][newfc];
                                    arr[newlc] += cur;
                                    if (arr[newlc] >= MOD) arr[newlc] -= MOD;
                                }
                        }
            for (int fd = 0; fd < 2; ++fd)
                for (int ld = 0; ld < 2; ++ld) {
                    int[][] arr = newdp[fd][ld];
                    if (fd == 0 && ld == 1) {
                        int lastDelta = ld == 0 ? 1 : -1;
                        int lastMin = lastDelta == 1 ? 0 : w - 1;
                        int lastMax = lastDelta == 1 ? w : -1;
                        for (int lc = lastMin; lc != lastMax; lc += lastDelta) {
                            for (int fc = 0; fc <= lc; ++fc) {
                                int cur = arr[fc][lc];
                                if (cur == 0) continue;
                                int newlc = lc + lastDelta;
                                if (newlc >= fc && newlc < w) {
                                    arr[fc][newlc] += cur;
                                    if (arr[fc][newlc] >= MOD) arr[fc][newlc] -= MOD;
                                }
                            }
                        }
                        int firstDelta = fd == 0 ? -1 : 1;
                        int firstMin = firstDelta == 1 ? 0 : w - 1;
                        int firstMax = firstDelta == 1 ? w : -1;
                        for (int fc = firstMin; fc != firstMax; fc += firstDelta) {
                            for (int lc = fc; lc < w; ++lc) {
                                int cur = arr[fc][lc];
                                if (cur == 0) continue;
                                int newfc = fc + firstDelta;
                                if (newfc >= 0 && newfc <= lc) {
                                    arr[newfc][lc] += cur;
                                    if (arr[newfc][lc] >= MOD) arr[newfc][lc] -= MOD;
                                }
                            }
                        }
                    } else {
                        int firstDelta = fd == 0 ? -1 : 1;
                        int firstMin = firstDelta == 1 ? 0 : w - 1;
                        int firstMax = firstDelta == 1 ? w : -1;
                        for (int fc = firstMin; fc != firstMax; fc += firstDelta) {
                            for (int lc = fc; lc < w; ++lc) {
                                int cur = arr[fc][lc];
                                if (cur == 0) continue;
                                int newfc = fc + firstDelta;
                                if (newfc >= 0 && newfc <= lc) {
                                    arr[newfc][lc] += cur;
                                    if (arr[newfc][lc] >= MOD) arr[newfc][lc] -= MOD;
                                }
                            }
                        }
                        int lastDelta = ld == 0 ? 1 : -1;
                        int lastMin = lastDelta == 1 ? 0 : w - 1;
                        int lastMax = lastDelta == 1 ? w : -1;
                        for (int lc = lastMin; lc != lastMax; lc += lastDelta) {
                            for (int fc = 0; fc <= lc; ++fc) {
                                int cur = arr[fc][lc];
                                if (cur == 0) continue;
                                int newlc = lc + lastDelta;
                                if (newlc >= fc && newlc < w) {
                                    arr[fc][newlc] += cur;
                                    if (arr[fc][newlc] >= MOD) arr[fc][newlc] -= MOD;
                                }
                            }
                        }
                    }
                }
            for (int fc = 0; fc < w; ++fc) {
                boolean ok = true;
                for (int lc = fc; lc < w; ++lc) {
                    if (myf[row][lc])
                        ok = false;
                    if (!ok) {
                        for (int fd = 0; fd < 2; ++fd)
                            for (int ld = 0; ld < 2; ++ld)
                                newdp[fd][ld][fc][lc] = 0;
                   } else {
                        newdp[0][0][fc][lc] += 1;
                        if (newdp[0][0][fc][lc] >= MOD) newdp[0][0][fc][lc] -= MOD;
                    }
                }
            }
            dp = newdp;
            for (int fd = 0; fd < 2; ++fd)
                for (int ld = 0; ld < 2; ++ld)
                    for (int fc = 0; fc < w; ++fc)
                        for (int lc = fc; lc < w; ++lc) {
                            totaldp += dp[fd][ld][fc][lc];
                            if (totaldp >= MOD) totaldp -= MOD;
                        }
        }
        return totaldp;
    }

public void solve(int testNumber, FastScanner in, PrintWriter out) {
		int numSongs = in.nextInt();
		Song[] songs = new Song[numSongs];
		List<Event> events = new ArrayList<Event>();
		for (int i = 0; i < numSongs; i++) {
			int l = in.nextInt();
			int r = in.nextInt();
			songs[i] = new Song(l, r, i);
			events.add(new Event(l, i, 1));
		}
		int numSingers = in.nextInt();
		Singer[] singers = new Singer[numSingers];
		tree = new int[numSingers];
		for (int i = 0; i < numSingers; i++) {
			int l = in.nextInt();
			int r = in.nextInt();
			int k = in.nextInt();
			singers[i] = new Singer(l, r, k, i);
			events.add(new Event(l, i, 0));
			events.add(new Event(r, i, 2));
		}
		Collections.sort(events);
		Singer[] sortedSingers = singers.clone();
		Arrays.sort(sortedSingers);
		int[] ans = new int[numSongs];
		boolean ok = true;
		for (Event e : events) {
			if (e.type == 0) {
				int pos = Arrays.binarySearch(sortedSingers, singers[e.id]);
				add(pos, +1);
			} else if (e.type == 1) {
				int l = -1;
				int r = numSingers - 1;
				int need = songs[e.id].r;


				while (r - l > 1) {
					int m = (l + r) / 2;
					Singer s = sortedSingers[m];
					if (s.r >= need) {
						r = m;
					} else {
						l = m;
					}
				}
				if (sortedSingers[r].r < need) {
					ok = false;
					break;
				}

				int first = r;
				l = first - 1;
				r = numSingers - 1;
				if (sum(first, numSingers - 1) == 0) {
					ok = false;
					break;
				}
				while (r - l > 1) {
					int m = (l + r) / 2;
					if (sum(first, m) > 0) {
						r = m;
					} else {
						l = m;
					}
				}
				Singer best = sortedSingers[r];
				--best.k;
				if (best.k == 0) {
					add(r, -1);
				}
				ans[e.id] = best.id;
			} else {
				int pos = Arrays.binarySearch(sortedSingers, singers[e.id]);
				if (singers[e.id].k > 0) {
					add(pos, -1);
				}
			}
		}
		if (!ok) {
			out.println("NO");
			return;
		}
		out.println("YES");
		for (int i = 0; i < numSongs; i++) {
			if (i > 0) {
				out.print(" ");
			}
			out.print(ans[i] + 1);
		}
		out.println();
	}

