static void solve() {
        int n = sc.nextInt();
        int k = sc.nextInt();
        char[] s = sc.next().toCharArray();

        if (k == n){
            int ones = 0;
            int zeros = 0;
            for (char i: s){
                if (i == '1'){
                    ones += 1;
                }
                if (i == '0'){
                    zeros += 1;
                }
            }
            if (ones > k / 2 || zeros > k / 2){
                pw.println("NO");
                return;
            }
        }
        for (int i = 0; i < n - k; i ++){
            if (s[i] != '?'){
                if (s[i + k] != '?'){
                    if (s[i + k] != s[i]){
                        pw.println("NO");
                        return;
                    }
                } else {
                    s[i + k] = s[i];
                }
            }
        }
        for (int i = n - 1; i >= k; i --){
            if (s[i] != '?'){
                if (s[i - k] != '?'){
                    if (s[i - k] != s[i]){
                        pw.println("NO");
                        return;
                    }
                } else {
                    s[i - k] = s[i];
                }
            }
        }
        for (int i = 0; i < n - k; i ++){
            if (s[i] != '?'){
                if (s[i + k] != '?'){
                    if (s[i + k] != s[i]){
                        pw.println("NO");
                        return;
                    }
                } else {
                    s[i + k] = s[i];
                }
            }
        }
        int start = 0;
        int end = k - 1;
        int ones = 0;
        int zeros = 0;
        for (int i = start; i <= end; i ++){
            if (s[i] == '1'){
                ones += 1;
            }
            if (s[i] == '0'){
                zeros += 1;
            }
        }
        if (ones > k / 2 || zeros > k / 2){
            pw.println("NO");
            return;
        }
        while (end != n - 1){
            if (s[end + 1] == '0'){
                zeros += 1;
            }
            if (s[end + 1] == '1'){
                ones += 1;
            }
            if (s[start] == '0'){
                zeros -= 1;
            }
            if (s[start] == '1'){
                ones -= 1;
            }
            start += 1;
            end += 1;
            if (ones > k / 2 || zeros > k / 2){
                pw.println("NO");
                return;
            }
        }
        pw.println("YES");
    }

