		while (t-- > 0) {
			String[] scn = (br.readLine()).trim().split(" ");
			int n = Integer.parseInt(scn[0]);
			int x = Integer.parseInt(scn[1]);

			int[] arr = new int[n];
			scn = (br.readLine()).trim().split(" ");
			for (int i = 0; i < n; i++) {
				arr[i] = Integer.parseInt(scn[i]);
			}
			if (n == 2) {
				if (arr[0] <= arr[1]) {
					sb.append("0");
				} else {
					if (arr[0] > x && x <= arr[1]) {
						sb.append("1");
					} else {
						sb.append("-1");
					}
				}
				sb.append("\n");
				continue;

			}

			boolean can = true;
			int ans = 0;
			int prev = arr[0];
			for (int i = 1; i < n; i++) {
				if (arr[i] >= prev) {
					prev = arr[i];
				} else {
					int j = i - 2;
					boolean great = false;
					if (j >= 0 && arr[j] <= arr[i]) {
						int k = j;
						while (k >= 0) {
							if (arr[k] > x) {
								k -= 1;
								great = true;
							} else {
								break;
							}
						}
						if (!great) {
							if (i - 1 > 0 && x < arr[i - 1] && x <= arr[i]) {
								ans += 1;
								int temp = x;
								x = arr[i - 1];
								arr[i - 1] = temp;
							}
						} else {
							k += 1;
							ans += j - k + 2;
							while (k <= j) {
								int temp = arr[k];
								arr[k] = x;
								x = temp;
								k += 1;
							}
							int temp = arr[k];
							arr[k] = x;
							x = temp;
							k += 1;
						}
					} else {
						can = false;
						break;
					}
				}
			}
			if (can) {
				sb.append(ans);
			} else {
				sb.append("-1");
			}
			sb.append("\n");

		}
		System.out.println(sb);
		return;
	}

