			boolean[][] mb = new boolean[m][n];
			for (int i = 0; i < m; i++) {
				String ss = in.nextLine();
				int x = ss.indexOf(':');
				String at = ss.substring(0, x);
				for (int j = 0; j < n; j++) {
					if (at.equals(s[j])) {
						a[i] = j;
					}
				}
				ms[i] = ss.substring(x + 1, ss.length());
				if (a[i] >= 0) {
					continue;
				}
				for (int j = 0; j < n; j++) {
					String[] sss = ms[i].split("[., !?]");
					boolean bbb = false;
					for (int q = 0; q < sss.length; q++) {
						if (sss[q].equals(s[j])) {
							bbb = true;
						}
					}
					mb[i][j] = bbb;
				}
			}

			for (int i = 0; i < m; i++) {
				if (a[i] >= 0) {
					continue;
				}
				if ((i + 1 < m) && (a[i + 1] != -1)) {
					mb[i][a[i + 1]] = true;
				}
				if ((i - 1 >= 0) && (a[i - 1] != -1)) {
					mb[i][a[i - 1]] = true;
				}
			}
			int[] c = new int[m];
			for (int i = 0; i < m; i++) {
				if (a[i] >= 0) {
					continue;
				}
				c[i] = n;
				for (int j = 0; j < n; j++) {
					if (mb[i][j]) {
						c[i]--;
					}
				}
			}
			boolean stop = true;
			boolean imp = true;
			while ((imp) && (stop)) {
				stop = false;
				for (int i = 0; i < m; i++) {
					if (a[i] >= 0) {
						continue;
					}
					if (c[i] == 0) {
						imp = false;
						break;
					}
					if (c[i] == 1) {
						for (int j = 0; j < n; j++) {
							if (!mb[i][j]) {
								a[i] = j;
								break;
							}
						}
						if (i + 1 < m) {
							if (!mb[i + 1][a[i]]) {
								c[i + 1]--;
								mb[i + 1][a[i]] = true;
							}

						}
						if (i - 1 >= 0) {
							if (!mb[i - 1][a[i]]) {
								mb[i - 1][a[i]] = true;
								c[i - 1]--;
							}
						}
						stop = true;
						break;
					}
				}
			}
			if (!imp) {
				System.out.println("Impossible");
			} else {
				for (int i = 0; i < m; i++) {
					if (a[i] < 0) {
						for (int j = 0; j < n; j++) {
							if (!mb[i][j]) {
								a[i] = j;
								if (i + 1 < m) {
									mb[i + 1][a[i]] = true;
								}
								break;
							}
						}
					}
					System.out.println(s[a[i]] + ":" + ms[i]);
				}
			}

		}
	}

public void solve(int testNumber, FastScanner in, PrintWriter out) {
            for (int n = 1; n <= 6; n++) {
                Set<Integer> A = genDummy(n);
                Set<Integer> B = genSmart(n);
                for (int x : A) {
                    if (!B.contains(x)) {
                        System.out.println("did not generate: " + toString(x, n));
                    }
                }
                for (int x : B) {
                    if (!A.contains(x)) {
                        System.out.println("should not have generated: " + toString(x, n));
                    }
                }
            }

            final int MOD = 998244353;

            int numTests = in.nextInt();
            for (int test = 0; test < numTests; test++) {
                int n = in.nextInt();
                int[] a = new int[n];
                for (int i = 0; i < n; i++) {

                    a[n - 1 - i] = in.nextInt();
                }
                long[][] s = new long[2][n + 1];
                long[][] numSameParity = new long[2][n + 1];
                long[] sBoth = new long[n + 1];
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < 2; j++) {
                        s[j][i + 1] = s[j][i] + (i % 2 == j ? a[i] : 0);
                        numSameParity[j][i + 1] = numSameParity[j][i] + (i % 2 == j ? 1 : 0);
                    }
                    sBoth[i + 1] = sBoth[i] + a[i];
                }
                long sumAll = sBoth[n];

                long ans = 0;
                for (int i = 0; i <= n; i++) {
                    if (2 * sBoth[i] < sumAll) {
                        ++ans;
                    }
                }

                if (n >= 2) {
                    for (int first = 0; first < 2; first++) {
                        for (int last = 0; last < 2; last++) {
                            for (int pref = (first == 0 ? 1 : 0); pref <= n - 2; pref++) {
                                if (pref == n - 2) {
                                    if (last == 1) {
                                        continue;
                                    }
                                }


                                long sum1 = 0;
                                sum1 += (first == 1 ? a[0] : 0);
                                sum1 += (last == 1 ? a[n - 1] : 0);
                                sum1 += sBoth[pref + 1] - sBoth[1];
                                if (2 * sum1 > sumAll) {
                                    ++ans;
                                    if (ans >= MOD) {
                                        ans -= MOD;
                                    }
                                }
                                int l = pref + 1;
                                int r = n - 2;
                                int parity = pref % 2;
                                boolean no11 = (n - 2) % 2 == parity && last == 1;
                                if (no11) {
                                    --r;
                                }

                                while (r - l > 1) {
                                    int m = (l + r) / 2;
                                    long add = s[parity][m + 1] - s[parity][pref + 1];
                                    if (2 * (sum1 + add) > sumAll) {
                                        r = m;
                                    } else {
                                        l = m;
                                    }
                                }

                                if (l >= r) {
                                    continue;
                                }

                                long add = s[parity][r + 1] - s[parity][pref + 1];
                                if (2 * (sum1 + add) <= sumAll) {
                                    continue;
                                }
                                long here = numSameParity[parity][n - 1] - numSameParity[parity][r];
                                if (no11) {
                                    --here;
                                }
                                ans += here;
                                if (ans >= MOD) {
                                    ans -= MOD;
                                }
                            }
                        }
                    }
                }
                ans %= MOD;
                if (ans < 0) {
                    ans += MOD;
                }
                out.println(ans);
            }
        }

