            if (k == 0) {
                out.println(-1);
                continue;
            }
            int left, right;
            qSegment.left = nextInt() - 1;
            qSegment.right = nextInt() - 1;
            int bsResult = Collections.binarySearch(segments, qSegment, comparatorLeftInc);
            if (bsResult >= 0) left = bsResult;
            else {
                int ip = -bsResult - 1;
                left = ip;
            }

            bsResult = Collections.binarySearch(segments, qSegment, comparatorRightInc);
            if (bsResult >= 0) right = bsResult;
            else {
                int ip = -bsResult - 1;
                right = ip - 1;
            }
            if (right < left) out.println(-1);
            else out.println(getMin(1, 0, k - 1, left, right));
        }

    }

