                Arrays.fill(delta, -1);
                int cur = b;
                while (true) {
                        if (delta[cur] != -1)
                                break;
                        delta[cur] = cur / x;
                        cur = get(cur);
                }
                boolean[] was = new boolean[w];
                int v = 0;
                cur = b;
                long all = 0;
                while (true) {
                        if (was[cur])  {
                                v = cur;
                                break;
                        }
                        all += delta[cur];
                        was[cur] = true;
                        cur = get(cur);
                }
                long cyc = 0;
                int len = 0;
                Arrays.fill(was, false);
                cur = v;
                while (true) {
                        if (was[cur])  {
                                break;
                        }
                        cyc += delta[cur];
                        len++;
