        }

public E() {
		Scanner s = new Scanner();

		int n = s.nextInt();

		boolean[] person = new boolean[2*n]; 

		ArrayList<Integer>[] undirGraph = new ArrayList[2*n];
		ArrayList<Integer>[] revGraph = new ArrayList[2*n]; 
		for (int i = 0; i < 2*n; i++) {
			revGraph[i] = new ArrayList<Integer>();
			undirGraph[i] = new ArrayList<Integer>();
		}
		boolean[] loops = new boolean[2*n];

		for (int i = 0; i < n; i++) {
			int from = s.nextInt()-1;
			int to = s.nextInt()-1;


			if (from == to) {

				loops[from] = true;
			}
			revGraph[to].add(from);

			undirGraph[to].add(from);
			undirGraph[from].add(to);
			person[from] = true;
		}

		boolean[] visited = new boolean[2*n];

		long total = 1;


		for (int i = 0; i < 2*n; i++) {
			if (visited[i] || !loops[i]) {	
				continue;
			}

			Queue<Integer> q = new PriorityQueue<Integer>();
			q.add(i);

			while (!q.isEmpty()) {
				int cur = q.poll();
				visited[cur] = true; 
				ArrayList<Integer> successors = undirGraph[cur];
				for (int next : successors) {
					if (!visited[next]) {
						q.add(next);	
					}
				} 
			}

		}


		for (int i = 0; i < 2*n; i++) {
			int componentSize = 0;
			if (person[i] || visited[i]) {	
				continue;
			}
			Queue<Integer> q = new PriorityQueue<Integer>();
			q.add(i);

			while (!q.isEmpty()) {
				int cur = q.poll();
				componentSize++;
				visited[cur] = true; 
				ArrayList<Integer> successors = revGraph[cur];
				for (int next : successors) {
					q.add(next);
				} 
			}

			total *= componentSize;
			total %= mod;
		}


		for (int i = 0; i < 2*n; i++) {
			if (visited[i]) {	
				continue;
			}

			Queue<Integer> q = new PriorityQueue<Integer>();
			q.add(i);

			while (!q.isEmpty()) {
				int cur = q.poll();
				visited[cur] = true; 
				ArrayList<Integer> successors = undirGraph[cur];
				for (int next : successors) {
					if (!visited[next]) {
						q.add(next);	
					}
				} 
			}

			total *= 2; 
			total %= mod;
		}

		System.out.println(total);
	}

