	    for(int i=1;i<n;i++){
	        if(str.charAt(i-1)=='1'){
	            prev1Index[i]=i-1;
	        }
	        else{
	            prev1Index[i]=prev1Index[i-1];
	        }
	    }
	    next1Index[n-1]=n;
	    for(int i=n-2;i>=0;i--){
	        if(str.charAt(i+1)=='1'){
	            next1Index[i]=i+1;
	        }
	        else{
	            next1Index[i]=next1Index[i+1];
	        }
	    }
	    long ans=0;
	    int start=0,end=0;

