	        for(int i=0;i<n;){
	            if(str.charAt(i)=='0'){
	                int numZeros=0;
	                int j=i;
	                while(j<str.length() && str.charAt(j)=='0'){
	                    j++;
	                    numZeros++;
	                }
	                ans+=(1L*numZeros*(numZeros+1))/2;
	                i=j;
	            }
	            else{
	                i++;
	            }
	        }
	        return ans;
	    }


	    int num1s=0;

	    while(end<n){
	        if(str.charAt(end)=='1'){
	            num1s++;
	            if(num1s==k){
	                break;
	            }
	            end++;
	        }
	        else{
	            if(num1s==0){
	                start++;
	                end++;
	            }
	            else{
	                end++;
	            }
	        }
	    }

	    if(end>=n){
	        return 0;
	    }

	    while(end<n){
            int startingPoints=start-prev1Index[start];
            int endingPoints=next1Index[end]-end;
            ans+=(1L*startingPoints*endingPoints);
            end=next1Index[end];
            start=next1Index[start];
	    }
	    return ans;
	}

