        int[] val = new int[N];
        for (int i=0; i<N; i++)
            val[i] = in.nextInt();
        for (int i=0; i<M; i++) {
            int u = in.nextInt()-1;
            int v = in.nextInt()-1;
            int w = in.nextInt();
            edges[u].add(new Edge(v,w));
            edges[v].add(new Edge(u,w));
        }
        int[][] index = new int[2][N];
        long[][] dist = new long[2][N];
        int[][] list = new int[2][N];
        for (int i=0; i<2; i++) {
            int x = 0;
            PriorityQueue<State> q = new PriorityQueue<State>();
            Arrays.fill(dist[i], oo);
            dist[i][start[i]] = 0;
            q.offer(new State(start[i],0));
            while(!q.isEmpty()) {
                State cur = q.poll();
                if (dist[i][cur.pos] < cur.dist)
                    continue;
                index[i][cur.pos] = x++;
                list[i][index[i][cur.pos]] = cur.pos;
                for (Edge e : edges[cur.pos]) {
                    if (dist[i][e.dest] > dist[i][cur.pos]+e.dist) {
                        dist[i][e.dest] = dist[i][cur.pos]+e.dist;
                        q.offer(new State(e.dest, dist[i][e.dest]));
                    }
                }
            }
        }

        jump = new int[2][N][N];
        jumpVal = new long[2][N][N];
        for (int a=0; a<2; a++) {
            for (int other = 0; other < N; other++) {
                long curDist = oo;
                int minWithDist = N;
                int minAboveDist = N;
                long jumpSum = 0;
                for (int i=N-1; i>=0; i--) {
                    if (dist[1-a][list[a][i]] > (other == 0 ? -1 : dist[1-a][list[1-a][other-1]])) {
                    	if (dist[a][list[a][i]] < curDist) {
                    		curDist = dist[a][list[a][i]];
                    		minAboveDist = minWithDist;
                    		jumpSum = 0;
                    	}
                    	minWithDist = i;
                    	jumpSum += val[list[a][i]];
                    }
                    jump[a][other][i] = minAboveDist;
                    jumpVal[a][other][i] = jumpSum;
                }
            }
        }

        long ans = dp(0, 0, 0);
